{
  "name": "Banana Pro 影像创作中心",
  "description": "专业级 AI 图像编辑与生成工具，集成 Nano Banana 与 Nano Banana Pro 模型，提供智能修图与重塑创作功能。"
}

export enum ModelId {
  NANO_BANANA = 'gemini-2.5-flash-image',
  NANO_BANANA_PRO = 'gemini-3-pro-image-preview',
}

export enum AspectRatio {
  SQUARE = '1:1',
  PORTRAIT_3_4 = '3:4',
  PORTRAIT_4_5 = '4:5',
  PORTRAIT_9_16 = '9:16',
  LANDSCAPE_16_9 = '16:9',
}

export enum ImageSize {
  STD_1K = '1K',
  HD_2K = '2K',
}

export interface GeneratedImage {
  url: string;
  id: string;
}

export type EditMode = 'mask' | 'view';

export interface GenerationConfig {
  aspectRatio: AspectRatio;
  numberOfImages: number;
  imageSize?: ImageSize;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ModelId, AspectRatio, ImageSize } from '../types';

// Helper to check for AI Studio API key availability for Pro models
async function ensureApiKey(modelId: ModelId): Promise<void> {
  if (modelId === ModelId.NANO_BANANA_PRO) {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        if (typeof window.aistudio.openSelectKey === 'function') {
          await window.aistudio.openSelectKey();
          // Assume success after dialog interaction as per race condition guidance
        }
      }
    }
  }
}

// Initialize client right before use to ensure correct key usage
const getClient = (): GoogleGenAI => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateImageEdit = async (
  modelId: ModelId,
  imageBase64: string,
  prompt: string,
  maskBase64?: string
): Promise<string[]> => {
  await ensureApiKey(modelId);
  const ai = getClient();

  const parts: any[] = [
    {
      inlineData: {
        mimeType: 'image/png',
        data: imageBase64,
      },
    },
    { text: prompt },
  ];

  // If a mask is provided, we treat it as an additional image context 
  // or prompt guidance depending on model capability. 
  // For this implementation, we append it to parts to guide the edit.
  if (maskBase64) {
    parts.splice(1, 0, {
      inlineData: {
        mimeType: 'image/png',
        data: maskBase64,
      },
    });
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      // Note: responseMimeType is not supported for these image models
    });

    return extractImagesFromResponse(response);
  } catch (error) {
    console.error("Edit generation error:", error);
    throw error;
  }
};

export const generateImageRecreate = async (
  modelId: ModelId,
  prompt: string,
  refImageBase64: string | null,
  config: {
    aspectRatio: AspectRatio;
    numberOfImages: number;
    imageSize: ImageSize;
  }
): Promise<string[]> => {
  await ensureApiKey(modelId);
  const ai = getClient();

  const parts: any[] = [];

  if (refImageBase64) {
    parts.push({
      inlineData: {
        mimeType: 'image/png',
        data: refImageBase64,
      },
    });
  }

  parts.push({ text: prompt });

  const apiConfig: any = {
    aspectRatio: config.aspectRatio,
  };

  // imageSize is only for Pro
  if (modelId === ModelId.NANO_BANANA_PRO) {
    apiConfig.imageSize = config.imageSize;
  }

  // numberOfImages not strictly supported in standard generateContent for all models 
  // in the same way as Imagen, but we pass it if the SDK allows or loop.
  // The guide implies generateContent for 'gemini-2.5-flash-image'.
  // We will make parallel calls if the model doesn't return multiple candidates natively in one go,
  // or rely on the model's 'numberOfImages' config if supported by the specific backend version.
  // Current 'generateContent' config doesn't list numberOfImages in the guide for these specific models,
  // usually that's for 'generateImages' (Imagen). 
  // We will assume 1 image per call for reliability in this specific prompt context, 
  // but to match the UI "slider 1-4", we'll simulate it by calling it N times or finding multiple parts.

  // For the purpose of this specific app and the models (Banana/Banana Pro), 
  // we will try to fetch one high quality result per request to avoid timeout/complexity 
  // or loop in the component. Here we return 1 image for simplicity of the service, 
  // letting the component handle the loop if needed, or just return the single result.
  // *Correction*: We will try to return what the API returns.

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: apiConfig
      }
    });

    return extractImagesFromResponse(response);
  } catch (error) {
    console.error("Recreate generation error:", error);
    throw error;
  }
};

function extractImagesFromResponse(response: GenerateContentResponse): string[] {
  const images: string[] = [];

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData && part.inlineData.data) {
        images.push(`data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`);
      }
    }
  }

  return images;
}

declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

