import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ModelId } from '../types';
import { generateImageEdit } from '../services/geminiService';

interface EditModuleProps {
  modelId: ModelId;
}

const EditModule: React.FC<EditModuleProps> = ({ modelId }) => {
  const [image, setImage] = useState<HTMLImageElement | null>(null);
  const [imageBase64, setImageBase64] = useState<string | null>(null);
  const [maskBase64, setMaskBase64] = useState<string | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Handle Image Upload
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          setImage(img);
          setImageBase64(event.target?.result as string ? (event.target?.result as string).split(',')[1] : null);
          setResultImage(null);
          setMaskBase64(null);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  // Canvas Drawing Logic
  useEffect(() => {
    if (image && canvasRef.current && containerRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // Fit canvas to container while maintaining aspect ratio
      const containerWidth = containerRef.current.clientWidth;
      const scale = Math.min(containerWidth / image.width, 1);

      canvas.width = image.width;
      canvas.height = image.height;

      // Display style matches container width
      canvas.style.width = `${image.width * scale}px`;
      canvas.style.height = `${image.height * scale}px`;

      // Draw original image
      ctx.drawImage(image, 0, 0);
    }
  }, [image]);

  const startDrawing = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!image) return;
    setIsDrawing(true);
    draw(e);
  };

  const stopDrawing = () => {
    setIsDrawing(false);
    exportMask();
  };

  const draw = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.globalCompositeOperation = 'source-over';
    ctx.beginPath();
    ctx.arc(x, y, brushSize, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255, 0, 0, 0.4)'; // Semi-transparent red
    ctx.fill();
  };

  const exportMask = useCallback(() => {
    if (!canvasRef.current) return;
    // Note: In a real advanced app, we would export just the mask layer.
    // Here we export the current canvas state which is Image + Red Overlay.
    // For better API results, we might want to separate them, but we'll send the annotated image 
    // and rely on the model understanding the "red mask".
    const dataUrl = canvasRef.current.toDataURL('image/png');
    setMaskBase64(dataUrl.split(',')[1]);
  }, []);

  const handleGenerate = async () => {
    if (!imageBase64 || !prompt) return;
    setLoading(true);
    try {
      // If user drew a mask, use the masked image version as context if logic permits, 
      // or send original + text. 
      // Strategy: Send original image and text. If mask exists, mention it in prompt or send as secondary image.
      // To keep it simple and robust for this demo:
      const finalPrompt = maskBase64 
        ? `在红色标记的区域执行以下操作: ${prompt}`
        : prompt;

      const images = await generateImageEdit(
        modelId, 
        imageBase64, 
        finalPrompt,
        maskBase64 // Sending the annotated image as a hint if supported, or just relying on text
      );

      if (images.length > 0) {
        setResultImage(images[0]);
      }
    } catch (e) {
      console.error(e);
      alert('生成失败，请稍后重试');
    } finally {
      setLoading(false);
    }
  };

  const setPresetPrompt = (text: string) => {
    setPrompt(text);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Left: Canvas Area */}
      <div className="lg:col-span-2 space-y-4">
        <div 
          ref={containerRef}
          className="relative w-full bg-slate-900 border-2 border-dashed border-slate-700 rounded-lg min-h-[500px] flex items-center justify-center overflow-hidden group"
        >
          {!image && (
            <div className="text-center">
              <svg className="mx-auto h-12 w-12 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              <div className="mt-4 flex text-sm text-slate-400 justify-center">
                <label className="relative cursor-pointer bg-slate-800 rounded-md font-medium text-yellow-500 hover:text-yellow-400 focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-yellow-500 px-4 py-2">
                  <span>上传图片</span>
                  <input type="file" className="sr-only" onChange={handleFileChange} accept="image/*" />
                </label>
                <p className="pl-1 pt-2">或拖拽至此处</p>
              </div>
            </div>
          )}
          {image && !resultImage && (
            <canvas
              ref={canvasRef}
              onMouseDown={startDrawing}
              onMouseMove={draw}
              onMouseUp={stopDrawing}
              onMouseLeave={stopDrawing}
              className="cursor-crosshair max-w-full shadow-2xl"
            />
          )}
           {resultImage && (
             <div className="relative">
                <img src={resultImage} alt="Result" className="max-w-full shadow-2xl" />
                <button 
                  onClick={() => setResultImage(null)}
                  className="absolute top-4 right-4 bg-black/60 text-white p-2 rounded-full hover:bg-black"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
             </div>
          )}

          {loading && (
            <div className="absolute inset-0 bg-black/70 flex items-center justify-center z-10">
              <div className="flex flex-col items-center">
                <div className="w-12 h-12 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin"></div>
                <p className="mt-4 text-yellow-500 font-mono text-sm animate-pulse">AI 处理中...</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Right: Controls */}
      <div className="space-y-6 bg-slate-800 p-6 rounded-lg border border-slate-700 h-fit">
        <div>
          <h3 className="text-lg font-semibold text-slate-100 mb-4 border-l-4 border-yellow-500 pl-3">编辑工具</h3>

          {image && !resultImage && (
            <div className="mb-6">
              <label className="block text-xs font-medium text-slate-400 mb-2">画笔大小</label>
              <input 
                type="range" 
                min="5" 
                max="100" 
                value={brushSize} 
                onChange={(e) => setBrushSize(Number(e.target.value))}
                className="w-full h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-yellow-500"
              />
            </div>
          )}

          <div className="space-y-4">
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-2">局部修复指令</label>
              <textarea
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder="例如：移除路人，将红花改为蓝花..."
                className="w-full bg-slate-900 border border-slate-600 rounded-md py-2 px-3 text-sm text-slate-200 placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-yellow-500 h-24 resize-none"
              />
            </div>

            <div className="space-y-2">
              <p className="text-xs font-medium text-slate-400">一键换幕</p>
              <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={() => setPresetPrompt('将背景替换为专业的摄影棚绿幕背景')}
                  className="px-3 py-2 bg-slate-700 hover:bg-slate-600 text-xs text-slate-200 rounded text-center transition-colors"
                >
                  标准绿幕
                </button>
                <button 
                   onClick={() => setPresetPrompt('将背景替换为专业的摄影棚蓝幕背景')}
                  className="px-3 py-2 bg-slate-700 hover:bg-slate-600 text-xs text-slate-200 rounded text-center transition-colors"
                >
                  标准蓝幕
                </button>
              </div>
            </div>

            <div className="space-y-2">
              <p className="text-xs font-medium text-slate-400">智能扩图 (宽高比)</p>
              <div className="grid grid-cols-3 gap-2">
                 <button onClick={() => setPresetPrompt('调整图片比例为 1:1，并自动填充扩展区域内容')} className="bg-slate-700 hover:bg-slate-600 text-xs py-1 rounded">1:1</button>
                 <button onClick={() => setPresetPrompt('调整图片比例为 4:5，并自动填充扩展区域内容')} className="bg-slate-700 hover:bg-slate-600 text-xs py-1 rounded">4:5</button>
                 <button onClick={() => setPresetPrompt('调整图片比例为 9:16，并自动填充扩展区域内容')} className="bg-slate-700 hover:bg-slate-600 text-xs py-1 rounded">9:16</button>
              </div>
            </div>
          </div>
        </div>

        <button
          onClick={handleGenerate}
          disabled={!image || !prompt || loading}
          className={`w-full py-3 rounded-md font-bold text-sm uppercase tracking-wider transition-all
            ${!image || !prompt || loading 
              ? 'bg-slate-600 text-slate-400 cursor-not-allowed' 
              : 'bg-gradient-to-r from-yellow-500 to-amber-600 text-slate-900 hover:from-yellow-400 hover:to-amber-500 shadow-lg shadow-yellow-500/20'}`}
        >
          {loading ? '处理中...' : '开始执行'}
        </button>
      </div>
    </div>
  );
};

export default EditModule;

import React, { useState } from 'react';
import { ModelId, AspectRatio, ImageSize } from '../types';
import { generateImageRecreate } from '../services/geminiService';

interface RecreateModuleProps {
  modelId: ModelId;
}

const RecreateModule: React.FC<RecreateModuleProps> = ({ modelId }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [refImageBase64, setRefImageBase64] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [count, setCount] = useState(1);
  const [quality, setQuality] = useState<ImageSize>(ImageSize.STD_1K);
  const [results, setResults] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setRefImage(event.target?.result as string);
        setRefImageBase64(event.target?.result as string ? (event.target?.result as string).split(',')[1] : null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt) return;
    setLoading(true);
    setResults([]);

    try {
      // Loop to simulate multiple images if needed, or just one call if the user selected 1.
      // For simplicity and stability in this demo, we fire parallel requests if count > 1
      // Note: Pro model might have rate limits, but we'll implement the logic.

      const promises = Array.from({ length: count }).map(() => 
        generateImageRecreate(modelId, prompt, refImageBase64, {
          aspectRatio,
          numberOfImages: 1, // Single per request for better control
          imageSize: quality
        })
      );

      const responses = await Promise.all(promises);
      const allImages = responses.flat();
      setResults(allImages);

    } catch (e) {
      console.error(e);
      alert('生成失败，请检查网络或 Key 状态');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full">
      {/* Sidebar: Config */}
      <div className="lg:col-span-4 space-y-6 bg-slate-800 p-6 rounded-lg border border-slate-700 h-fit">
         <h3 className="text-lg font-semibold text-slate-100 mb-4 border-l-4 border-yellow-500 pl-3">创作参数</h3>

         {/* Reference Image */}
         <div className="space-y-2">
           <label className="text-xs font-medium text-slate-400">参考图 (可选)</label>
           <div className="flex items-center space-x-4">
             <div className="w-20 h-20 bg-slate-900 rounded border border-slate-600 flex items-center justify-center overflow-hidden">
                {refImage ? (
                  <img src={refImage} alt="Ref" className="w-full h-full object-cover" />
                ) : (
                  <span className="text-slate-600 text-xs">无</span>
                )}
             </div>
             <label className="cursor-pointer bg-slate-700 hover:bg-slate-600 text-slate-200 px-3 py-1.5 rounded text-xs transition-colors">
               选择图片
               <input type="file" className="hidden" onChange={handleFileChange} accept="image/*" />
             </label>
             {refImage && <button onClick={() => {setRefImage(null); setRefImageBase64(null)}} className="text-red-400 text-xs hover:text-red-300">清除</button>}
           </div>
         </div>

         {/* Prompt */}
         <div>
            <label className="block text-xs font-medium text-slate-400 mb-2">画面描述</label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="描述你想要生成的画面细节、光影、风格..."
              className="w-full bg-slate-900 border border-slate-600 rounded-md py-2 px-3 text-sm text-slate-200 placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-yellow-500 h-32 resize-none"
            />
         </div>

         {/* Parameters */}
         <div className="space-y-4 pt-4 border-t border-slate-700">
            {/* Aspect Ratio */}
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-2">画面比例</label>
              <div className="grid grid-cols-5 gap-2">
                {[AspectRatio.PORTRAIT_3_4, AspectRatio.PORTRAIT_4_5, AspectRatio.PORTRAIT_9_16, AspectRatio.SQUARE, AspectRatio.LANDSCAPE_16_9].map(ratio => (
                  <button
                    key={ratio}
                    onClick={() => setAspectRatio(ratio)}
                    className={`text-xs py-1.5 rounded border ${aspectRatio === ratio ? 'bg-yellow-500/20 border-yellow-500 text-yellow-500' : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                  >
                    {ratio}
                  </button>
                ))}
              </div>
            </div>

            {/* Count Slider */}
            <div>
               <div className="flex justify-between mb-2">
                 <label className="text-xs font-medium text-slate-400">生成数量</label>
                 <span className="text-xs font-mono text-yellow-500">{count}</span>
               </div>
               <input 
                 type="range" min="1" max="4" value={count} onChange={(e) => setCount(Number(e.target.value))}
                 className="w-full h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-yellow-500"
               />
            </div>

            {/* Quality (Only for Pro) */}
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-2">画质选择</label>
              <div className="grid grid-cols-2 gap-3">
                 <button
                   onClick={() => setQuality(ImageSize.STD_1K)}
                   className={`text-xs py-2 rounded flex flex-col items-center justify-center border ${quality === ImageSize.STD_1K ? 'bg-yellow-500/10 border-yellow-500 text-slate-200' : 'bg-slate-900 border-slate-700 text-slate-500'}`}
                 >
                   <span className="font-bold">标准 (1K)</span>
                   <span className="text-[10px] opacity-60">适用于快速预览</span>
                 </button>
                 <button
                   disabled={modelId !== ModelId.NANO_BANANA_PRO}
                   onClick={() => setQuality(ImageSize.HD_2K)}
                   className={`text-xs py-2 rounded flex flex-col items-center justify-center border transition-all
