import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ModelId, AspectRatio, ImageSize } from '../types';

// Helper to check for AI Studio API key availability for Pro models
async function ensureApiKey(modelId: ModelId): Promise<void> {
  if (modelId === ModelId.NANO_BANANA_PRO) {
    const win = window as any;
    if (win.aistudio && typeof win.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await win.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        if (typeof win.aistudio.openSelectKey === 'function') {
          await win.aistudio.openSelectKey();
          // Assume success after dialog interaction as per race condition guidance
        }
      }
    }
  }
}

// Initialize client right before use to ensure correct key usage
const getClient = (): GoogleGenAI => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const generateImageEdit = async (
  modelId: ModelId,
  imageBase64: string,
  prompt: string,
  maskBase64?: string
): Promise<string[]> => {
  await ensureApiKey(modelId);
  const ai = getClient();

  const parts: any[] = [
    {
      inlineData: {
        mimeType: 'image/png',
        data: imageBase64,
      },
    },
    { text: prompt },
  ];

  // If a mask is provided, we treat it as an additional image context 
  // or prompt guidance depending on model capability. 
  // For this implementation, we append it to parts to guide the edit.
  if (maskBase64) {
    parts.splice(1, 0, {
      inlineData: {
        mimeType: 'image/png',
        data: maskBase64,
      },
    });
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      // Note: responseMimeType is not supported for these image models
    });

    return extractImagesFromResponse(response);
  } catch (error) {
    console.error("Edit generation error:", error);
    throw error;
  }
};

export const generateImageRecreate = async (
  modelId: ModelId,
  prompt: string,
  refImageBase64: string | null,
  config: {
    aspectRatio: AspectRatio;
    numberOfImages: number;
    imageSize: ImageSize;
  }
): Promise<string[]> => {
  await ensureApiKey(modelId);
  const ai = getClient();

  const parts: any[] = [];

  if (refImageBase64) {
    parts.push({
      inlineData: {
        mimeType: 'image/png',
        data: refImageBase64,
      },
    });
  }

  parts.push({ text: prompt });

  const apiConfig: any = {
    aspectRatio: config.aspectRatio,
  };

  // imageSize is only for Pro
  if (modelId === ModelId.NANO_BANANA_PRO) {
    apiConfig.imageSize = config.imageSize;
  }

  // numberOfImages not strictly supported in standard generateContent for all models 
  // in the same way as Imagen, but we pass it if the SDK allows or loop.
  // The guide implies generateContent for 'gemini-2.5-flash-image'.
  // We will make parallel calls if the model doesn't return multiple candidates natively in one go,
  // or rely on the model's 'numberOfImages' config if supported by the specific backend version.
  // Current 'generateContent' config doesn't list numberOfImages in the guide for these specific models,
  // usually that's for 'generateImages' (Imagen). 
  // We will assume 1 image per call for reliability in this specific prompt context, 
  // but to match the UI "slider 1-4", we'll simulate it by calling it N times or finding multiple parts.

  // For the purpose of this specific app and the models (Banana/Banana Pro), 
  // we will try to fetch one high quality result per request to avoid timeout/complexity 
  // or loop in the component. Here we return 1 image for simplicity of the service, 
  // letting the component handle the loop if needed, or just return the single result.
  // *Correction*: We will try to return what the API returns.

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: {
        imageConfig: apiConfig
      }
    });

    return extractImagesFromResponse(response);
  } catch (error) {
    console.error("Recreate generation error:", error);
    throw error;
  }
};

function extractImagesFromResponse(response: GenerateContentResponse): string[] {
  const images: string[] = [];

  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData && part.inlineData.data) {
        images.push(`data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`);
      }
    }
  }

  return images;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);

  // Tools
  const [activeTool, setActiveTool] = useState<'brush' | 'rect' | 'none'>('none');
  const [brushSize, setBrushSize] = useState(40); // Larger default
  const [isDrawing, setIsDrawing] = useState(false);

  // Data
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);

  // History for Undo
  const [history, setHistory] = useState<ImageData[]>([]);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPos = useRef<{x: number, y: number} | null>(null);
  const dragStartRef = useRef<{x: number, y: number} | null>(null);

  // Initialize Canvas Context helper
  const getCtx = () => canvasRef.current?.getContext('2d', { willReadFrequently: true });

  // Load Image
  const loadImage = useCallback((src: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setImage(src);
      setImageDimensions({ width: img.width, height: img.height });
      setResultImages([]);
      setHistory([]);

      // Setup Canvas
      if (canvasRef.current) {
         canvasRef.current.width = img.width;
         canvasRef.current.height = img.height;
         const ctx = getCtx();
         if (ctx) {
            ctx.clearRect(0, 0, img.width, img.height);
            // Save initial blank state
            const initialData = ctx.getImageData(0, 0, img.width, img.height);
            setHistory([initialData]);
         }
      }
    };
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        if (file.size > 10 * 1024 * 1024) {
            setError("文件大小不能超过 10MB");
            return;
        }
        const reader = new FileReader();
        reader.onload = (evt) => {
          if (evt.target?.result) loadImage(evt.target.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  // --- UNDO LOGIC ---
  const saveHistory = () => {
    const ctx = getCtx();
    if (ctx && canvasRef.current) {
        const data = ctx.getImageData(0, 0, canvasRef.current.width, canvasRef.current.height);
        setHistory(prev => {
            const newHistory = [...prev, data];
            // Limit history
            return newHistory.slice(-20);
        });
    }
  };

  const undo = () => {
    if (history.length <= 1) return;
    const ctx = getCtx();
    if (ctx) {
        // Remove current state
        const newHistory = history.slice(0, -1);
        // Restore previous state
        const prevState = newHistory[newHistory.length - 1];
        ctx.putImageData(prevState, 0, 0);
        setHistory(newHistory);
    }
  };

  // --- DRAWING ENGINE ---
  const getCoordinates = (e: React.PointerEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    // Map CSS pixels to Canvas pixels
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none') return;
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDrawing(true);

    const { x, y } = getCoordinates(e);
    lastPos.current = { x, y };
    dragStartRef.current = { x, y };

    const ctx = getCtx();
    if (!ctx) return;

    if (activeTool === 'brush') {
        // IMPORTANT: Brush Settings for Roundness
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.lineWidth = brushSize;
        ctx.globalCompositeOperation = 'source-over';
        // Use solid red for mask. We use CSS opacity on the canvas to make it see-through.
        // This prevents the "dots" artifact from overlapping semi-transparent strokes.
        ctx.strokeStyle = '#ff0000'; 

        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x, y); // Draw a dot
        ctx.stroke();
    }
  };

  const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (!isDrawing || !canvasRef.current) return;
    const { x, y } = getCoordinates(e);
    const ctx = getCtx();
    if (!ctx) return;

    if (activeTool === 'brush') {
        if (!lastPos.current) return;
        ctx.beginPath();
        ctx.moveTo(lastPos.current.x, lastPos.current.y);
        ctx.lineTo(x, y);
        ctx.stroke();
        lastPos.current = { x, y };
    } else if (activeTool === 'rect') {
        // Redraw rect dynamically: Restore last history state then draw rect
        if (history.length > 0 && dragStartRef.current) {
            const lastState = history[history.length - 1];
            ctx.putImageData(lastState, 0, 0);

            ctx.fillStyle = 'rgba(255, 0, 0, 1)'; // Solid red
            const startX = dragStartRef.current.x;
            const startY = dragStartRef.current.y;
            ctx.fillRect(startX, startY, x - startX, y - startY);
        }
    }
  };

  const stopDrawing = (e: React.PointerEvent) => {
    if (isDrawing) {
        setIsDrawing(false);
        e.currentTarget.releasePointerCapture(e.pointerId);
        lastPos.current = null;
        dragStartRef.current = null;
        saveHistory();
    }
  };

  // --- API ---
  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;
    setIsLoading(true);
    setError(null);

    try {
      let maskBase64: string | undefined = undefined;

      // Extract Mask if needed
      if (!skipMask && canvasRef.current) {
         // Check if canvas is not blank
         const ctx = getCtx();
         // Simple check: do we have history > 1 (meaning user drew something)?
         if (history.length > 1) {
             const dataUrl = canvasRef.current.toDataURL('image/png');
             maskBase64 = dataUrl;
         }
      }

      const res = await editImageWithGemini({
        model,
        imageBase64: image,
        maskBase64,
        prompt: overridePrompt || prompt,
        aspectRatio: aspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleCleanImage = () => {
    // Force prompt that works well for cleanup without mask
    const cleanPrompt = "Inpaint the image to remove all text, watermarks, subtitles, logos, and icons. Blend the removed areas seamlessly with the surrounding background.";
    handleGenerate(cleanPrompt, true); // true = skip mask
  };

  const useAsInput = (imgUrl: string) => {
     loadImage(imgUrl);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">

      {/* LEFT: WORKSPACE */}
      <div className="flex flex-col gap-4 h-full">

         {/* Toolbar */}
         <div className="bg-gray-900/80 backdrop-blur border border-gray-800 p-3 rounded-xl flex flex-wrap items-center justify-between gap-3 shrink-0">
            <div className="flex items-center gap-2">
                {!image && (
                    <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-1.5 rounded-lg text-sm font-bold transition-colors">
                        上传图片
                        <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                    </label>
                )}
                {image && (
                    <>
                     <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700">
                        <button 
                            onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                            className={`px-3 py-1.5 rounded text-sm flex items-center gap-2 font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            <span className="w-3 h-3 rounded-full bg-current"></span> 涂抹
                        </button>
                        <button 
                            onClick={() => setActiveTool(activeTool === 'rect' ? 'none' : 'rect')}
                            className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'rect' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            🔳 框选
                        </button>
                     </div>
                     <button onClick={undo} disabled={history.length <= 1} className="p-2 text-gray-400 hover:text-white disabled:opacity-30">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"></path></svg>
                     </button>
                     <button onClick={() => {setImage(null); setResultImages([]); setHistory([]);}} className="p-2 text-red-400 hover:text-red-300">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                     </button>
                    </>
                )}
            </div>

            {image && activeTool === 'brush' && (
                <div className="flex items-center gap-2">
                    <span className="text-xs text-gray-500">笔刷</span>
                    <input 
                        type="range" min="10" max="150" 
                        value={brushSize} onChange={(e) => setBrushSize(Number(e.target.value))}
                        className="w-24 accent-indigo-500 h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                    />
                </div>
            )}
         </div>

         {/* Canvas Container */}
         <div 
            ref={containerRef}
            className={`relative flex-1 bg-gray-900 border-2 rounded-xl overflow-hidden flex items-center justify-center
                ${!image ? 'border-dashed border-gray-800' : 'border-gray-800 bg-checkered'}
            `}
         >
            {!image ? (
                <div className="text-center text-gray-600 pointer-events-none">
                    <svg className="w-12 h-12 mx-auto mb-2 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    <p>拖拽或点击上传</p>
                </div>
            ) : (
                <div className="relative max-w-full max-h-full shadow-2xl">
                    <img src={image} className="max-w-full max-h-[60vh] object-contain block" alt="Source" draggable={false} />
                    {/* Canvas Overlay with CSS Opacity for "See-through" Mask */}
                    <canvas 
                        ref={canvasRef}
                        onPointerDown={startDrawing}
                        onPointerMove={draw}
                        onPointerUp={stopDrawing}
                        onPointerLeave={stopDrawing}
                        className={`absolute inset-0 w-full h-full opacity-60 touch-none ${activeTool !== 'none' ? 'cursor-crosshair' : ''}`}
                    />
                </div>
            )}
            {!image && (
                 <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleFileUpload} />
            )}
         </div>

         {/* Action Bar */}
         <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 shrink-0 space-y-3">
             <div className="flex gap-3">
                <input 
                    type="text" 
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="在此输入编辑指令 (例如：移除画面中的路人)..."
                    className="flex-1 bg-gray-900 border border-gray-600 rounded-lg px-4 py-2 text-white placeholder-gray-500 focus:ring-2 focus:ring-yellow-500 outline-none"
                />
                <div className="w-32">
