import React, { useState } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [imageDimensions, setImageDimensions] = useState<{width: number, height: number} | null>(null);

  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);
  const [count, setCount] = useState(1);
  const [quality, setQuality] = useState<ImageResolution>(ImageResolution.RES_1K);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  const validateAndSetImage = (file: File) => {
    if (file.size > 10 * 1024 * 1024) {
      setError("文件大小不能超过 10MB");
      return;
    }
    const reader = new FileReader();
    reader.onload = (evt) => {
      const src = evt.target?.result as string;
      setRefImage(src);
      setError(null);
      const img = new Image();
      img.src = src;
      img.onload = () => {
        setImageDimensions({ width: img.width, height: img.height });
      };
    };
    reader.readAsDataURL(file);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) validateAndSetImage(file);
  };

  // Drag & Drop
  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) validateAndSetImage(file);
  };

  const handleGenerate = async () => {
    if (!refImage || !prompt) return;
    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      // Calculate Ratio
      let finalAspectRatio = aspectRatio;
      if (finalAspectRatio === AspectRatio.ORIGINAL && imageDimensions) {
         const ratio = imageDimensions.width / imageDimensions.height;
         // Simple snap to closest
         if (ratio > 1.3) finalAspectRatio = AspectRatio.LANDSCAPE_16_9;
         else if (ratio < 0.8) finalAspectRatio = AspectRatio.PORTRAIT_9_16;
         else finalAspectRatio = AspectRatio.SQUARE;
      } else if (finalAspectRatio === AspectRatio.ORIGINAL) {
         finalAspectRatio = AspectRatio.SQUARE;
      }

      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt,
        aspectRatio: finalAspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const useAsReference = (imgUrl: string) => {
     setRefImage(imgUrl);
     // Also update dimensions
     const img = new Image();
     img.src = imgUrl;
     img.onload = () => {
        setImageDimensions({ width: img.width, height: img.height });
     };
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">

      {/* LEFT: CONFIG */}
      <div className="flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">

        {/* Reference Image Box */}
        <div 
          className={`shrink-0 bg-gray-900 rounded-xl border-2 border-dashed flex flex-col items-center justify-center p-6 transition-all min-h-[250px] relative group
             ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-gray-800'}
             ${refImage ? 'border-solid border-gray-700 p-0 overflow-hidden bg-black' : ''}
          `}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {!refImage ? (
             <div className="text-center">
                <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-500">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                </div>
                <label className="cursor-pointer text-yellow-500 hover:text-yellow-400 font-bold">
                    上传参考图
                    <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                </label>
                <p className="text-sm text-gray-500 mt-2">支持拖拽上传 (Max 10MB)</p>
             </div>
          ) : (
             <>
               <img src={refImage} alt="Reference" className="w-full h-full object-contain" />
               <button 
                  onClick={() => setRefImage(null)}
                  className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white p-2 rounded-full transition-colors backdrop-blur-sm opacity-0 group-hover:opacity-100"
               >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
               </button>
             </>
          )}
        </div>

        {/* Form */}
        <div className="bg-gray-900 border border-gray-800 rounded-xl p-6 space-y-6 flex-1">
           <div>
              <label className="block text-sm font-bold text-gray-400 mb-2 uppercase tracking-wider">创作描述</label>
              <textarea 
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                className="w-full h-32 bg-gray-800 border border-gray-700 rounded-lg p-4 text-white focus:ring-2 focus:ring-yellow-500 outline-none resize-none placeholder-gray-600"
                placeholder="描述你想要生成的画面，例如：'赛博朋克风格的城市夜景'..."
              ></textarea>
           </div>

           <div className="grid grid-cols-2 gap-4">
              <Select label="画幅比例" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                <option value={AspectRatio.ORIGINAL}>保持原图比例</option>
                <option value={AspectRatio.SQUARE}>1:1 正方形</option>
                <option value={AspectRatio.PORTRAIT_3_4}>3:4 竖幅</option>
                <option value={AspectRatio.LANDSCAPE_16_9}>16:9 横幅</option>
              </Select>

              <Select label="画质精度" value={quality} onChange={(e) => setQuality(e.target.value as ImageResolution)}>
                <option value={ImageResolution.RES_1K}>标准 (1K)</option>
                <option value={ImageResolution.RES_2K}>高清 (2K Pro)</option>
              </Select>

              <div className="col-span-2">
                 <Select label="生成数量" value={count} onChange={(e) => setCount(Number(e.target.value))}>
                    <option value={1}>1 张</option>
