                    <option value={3}>3 张</option>
                    <option value={4}>4 张</option>
                 </Select>
              </div>
           </div>

           <Button 
             onClick={handleGenerate} 
             disabled={!refImage || !prompt} 
             isLoading={isLoading}
             className="w-full py-4 text-lg font-bold shadow-xl shadow-yellow-900/10"
           >
             🚀 开始重塑
           </Button>

           {error && (
              <div className="p-3 bg-red-900/30 border border-red-800 rounded text-red-300 text-sm">
                 {error}
              </div>
           )}
        </div>
      </div>

      {/* RIGHT: RESULTS */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 h-full flex flex-col">
         <div className="flex items-center justify-between mb-4 px-2">
            <h3 className="text-lg font-bold text-white">创作成果</h3>
            <span className="text-xs text-gray-500">生成结果展示区</span>
         </div>

         <div className="flex-1 overflow-y-auto custom-scrollbar p-2">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               {results.map((imgUrl, idx) => (
                  <div key={idx} className="group relative rounded-lg overflow-hidden border border-gray-700 bg-black aspect-auto">
