import { GoogleGenAI, Type, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { BananaModel, AspectRatio, ImageResolution } from "../types";

// Helper to ensure API Key is ready, especially for Pro models
const getClient = async (model: BananaModel): Promise<GoogleGenAI> => {
  if (model === BananaModel.NANO_BANANA_PRO) {
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  }

  // Create a new instance to ensure we pick up the latest key/env
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const extractImagesFromResponse = (response: any): string[] => {
  const images: string[] = [];

  if (!response.candidates || response.candidates.length === 0) {
    return images;
  }

  for (const candidate of response.candidates) {
    if (candidate.content && candidate.content.parts) {
      for (const part of candidate.content.parts) {
        if (part.inlineData) {
          const mimeType = part.inlineData.mimeType || 'image/png';
          const base64 = part.inlineData.data;
          images.push(`data:${mimeType};base64,${base64}`);
        }
      }
    }
  }
  return images;
};

interface EditImageParams {
  model: BananaModel;
  imageBase64: string; // The original image
  maskBase64?: string; // The drawn mask (optional)
  prompt: string;
  aspectRatio: AspectRatio;
}

export const editImageWithGemini = async ({
  model,
  imageBase64,
  maskBase64,
  prompt,
  aspectRatio
}: EditImageParams): Promise<string[]> => {
  const ai = await getClient(model);

  // Clean base64 strings
  const cleanImage = imageBase64.replace(/^data:image\/\w+;base64,/, "");

  const parts: any[] = [
    {
      inlineData: {
        data: cleanImage,
        mimeType: "image/png",
      },
    }
  ];

  // If a mask is provided, we add it as a second image part and instruct the model
  let finalPrompt = prompt;
  if (maskBase64) {
    const cleanMask = maskBase64.replace(/^data:image\/\w+;base64,/, "");
    parts.push({
      inlineData: {
        data: cleanMask,
        mimeType: "image/png",
      }
    });
    // Append instruction to use the second image as mask
    finalPrompt = `${prompt} (Note: The second image provided is a red mask indicating the area to edit. Only modify the masked area.)`;
  } else {
    // Global Edit (No Mask) - One Click Clean falls here
    // Ensure we don't accidentally restrict the model if it's Pro
    finalPrompt = `${prompt} Output high quality, photorealistic image.`;
  }

  parts.push({ text: finalPrompt });

  const config: any = {
    imageConfig: {
      aspectRatio: aspectRatio,
      numberOfImages: 1, // Explicitly set for consistency
    },
    // Permissive safety settings
    safetySettings: [
      { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
    ]
  };

  // Only Pro supports resolution config
  if (model === BananaModel.NANO_BANANA_PRO) {
     config.imageConfig.imageSize = "1K"; // Defaulting to 1K for edit for speed
  }

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: { parts },
      config: config
    });

    return extractImagesFromResponse(response);
  } catch (error: any) {
    console.error("Edit Image Error:", error);
    throw new Error(error.message || "图像编辑请求失败，请尝试调整提示词或重置画布。");
  }
};

interface RecreateImageParams {
  model: BananaModel;
  referenceImageBase64: string;
  prompt: string;
  aspectRatio: AspectRatio;
  numberOfImages: number;
  quality: ImageResolution;
}

export const recreateImageWithGemini = async ({
  model,
  referenceImageBase64,
  prompt,
  aspectRatio,
  numberOfImages,
  quality
}: RecreateImageParams): Promise<string[]> => {
  const ai = await getClient(model);
  const cleanRef = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");

  const parts = [
    {
      inlineData: {
        data: cleanRef,
        mimeType: "image/png", 
      },
    },
    {
      text: `基于提供的参考图，请按照以下要求生成新的图像：${prompt}`,
    },
  ];

  const config: any = {
    imageConfig: {
      aspectRatio: aspectRatio,
      numberOfImages: 1, // Base default
    },
    safetySettings: [
      { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
    ]
  };

  if (model === BananaModel.NANO_BANANA_PRO) {
    config.imageConfig.imageSize = quality;
  }

  try {
    // Parallel requests for count > 1
    const promises = Array.from({ length: numberOfImages }).map(() => 
      ai.models.generateContent({
        model: model,
        contents: { parts },
        config: config
      })
    );

    const responses = await Promise.all(promises);

    let allImages: string[] = [];
    responses.forEach(res => {
      allImages = [...allImages, ...extractImagesFromResponse(res)];
    });

    if (allImages.length === 0) {
      throw new Error("模型未返回任何图像数据，请检查提示词是否触犯安全限制。");
    }

    return allImages;

  } catch (error: any) {
    console.error("Recreate Image Error:", error);
    throw new Error(error.message || "重塑创作请求失败");
  }
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);

  // Tools
  const [activeTool, setActiveTool] = useState<'brush' | 'rect' | 'none'>('none');
  const [brushSize, setBrushSize] = useState(40);
  const [isDrawing, setIsDrawing] = useState(false);

  // Data
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);

  // History for Undo (Stores ImageData)
  // IMPORTANT: History index 0 is always the blank canvas state.
  const [history, setHistory] = useState<ImageData[]>([]);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPos = useRef<{x: number, y: number} | null>(null);

  // Setup Canvas Context
  const getCtx = useCallback(() => {
    return canvasRef.current?.getContext('2d', { willReadFrequently: true });
  }, []);

  // Initialize Canvas
  const initCanvas = useCallback((width: number, height: number) => {
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (ctx) {
            ctx.clearRect(0, 0, width, height);
            // Save initial blank state to history
            const blankState = ctx.getImageData(0, 0, width, height);
            setHistory([blankState]);
        }
    }
  }, []);

  // Load Image
  const loadImage = useCallback((src: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setImage(src);
      setResultImages([]);
      setHistory([]);
      initCanvas(img.width, img.height);
    };
  }, [initCanvas]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
          if (evt.target?.result) loadImage(evt.target.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const useAsInput = (imgUrl: string) => {
     loadImage(imgUrl);
  };

  // --- UNDO LOGIC ---
  const saveSnapshot = () => {
      const ctx = getCtx();
      const canvas = canvasRef.current;
      if (ctx && canvas) {
          const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
          setHistory(prev => {
              const newHistory = [...prev, data];
              return newHistory.slice(-20); // Keep last 20 steps
          });
      }
  };

  const undo = () => {
      if (history.length <= 1) return; // Always keep the initial blank state
      const newHistory = history.slice(0, -1);
      const prevState = newHistory[newHistory.length - 1];

      const ctx = getCtx();
      if (ctx && prevState) {
          ctx.putImageData(prevState, 0, 0);
          setHistory(newHistory);
      }
  };

  // --- DRAWING ENGINE (Fixing roundness) ---
  const getCoordinates = (e: React.PointerEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none') return;
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDrawing(true);

    const { x, y } = getCoordinates(e);
    lastPos.current = { x, y };

    const ctx = getCtx();
    if (!ctx) return;

    if (activeTool === 'brush') {
        // ROUND BRUSH SETTINGS
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.lineWidth = brushSize;
        ctx.strokeStyle = '#ff0000'; // Solid red, opacity handled by canvas CSS

        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x, y);
        ctx.stroke();
    }
  };

  const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (!isDrawing || activeTool !== 'brush') return;
    const { x, y } = getCoordinates(e);
    const ctx = getCtx();
    if (!ctx || !lastPos.current) return;

    ctx.beginPath();
    ctx.moveTo(lastPos.current.x, lastPos.current.y);
    ctx.lineTo(x, y);
    ctx.stroke();
    lastPos.current = { x, y };
  };

  const stopDrawing = (e: React.PointerEvent) => {
    if (isDrawing) {
        setIsDrawing(false);
        e.currentTarget.releasePointerCapture(e.pointerId);
        lastPos.current = null;
        saveSnapshot(); // Save state after stroke
    }
  };

  // --- API ---
  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;
    setIsLoading(true);
    setError(null);

    try {
      let maskBase64: string | undefined = undefined;

      // Extract Mask
      if (!skipMask && canvasRef.current && history.length > 1) {
          maskBase64 = canvasRef.current.toDataURL('image/png');
      }

      const res = await editImageWithGemini({
        model,
        imageBase64: image,
        maskBase64,
        prompt: overridePrompt || prompt,
        aspectRatio: aspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePreset = (presetPrompt: string, ratio?: AspectRatio) => {
      setPrompt(presetPrompt);
      if (ratio) setAspectRatio(ratio);
  };

  // One click clean should work even if history is empty (no mask)
  const canClean = !!image; 

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">

      {/* LEFT COLUMN: EDITOR */}
      <div className="flex flex-col gap-4 h-full">

