  };

  const handleGenerate = async () => {
    if (!refImage || !prompt) return;
    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt,
        aspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
