import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { BananaModel, AspectRatio, ImageResolution } from "../types";

// Helper to ensure API Key is ready, especially for Pro models
const getClient = async (model: BananaModel): Promise<GoogleGenAI> => {
  if (model === BananaModel.NANO_BANANA_PRO) {
    if (window.aistudio) {
      // Check for API key selection for Pro models
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  }

  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const extractImagesFromResponse = (response: any): string[] => {
  const images: string[] = [];

  if (!response.candidates || response.candidates.length === 0) {
    return images;
  }

  for (const candidate of response.candidates) {
    if (candidate.content && candidate.content.parts) {
      for (const part of candidate.content.parts) {
        if (part.inlineData) {
          const mimeType = part.inlineData.mimeType || 'image/png';
          const base64 = part.inlineData.data;
          images.push(`data:${mimeType};base64,${base64}`);
        }
      }
    }
  }
  return images;
};

interface EditImageParams {
  model: BananaModel;
  imageBase64: string; 
  maskBase64?: string; 
  prompt: string;
  aspectRatio: AspectRatio;
}

export const editImageWithGemini = async ({
  model,
  imageBase64,
  maskBase64,
  prompt,
  aspectRatio
}: EditImageParams): Promise<string[]> => {
  try {
    const ai = await getClient(model);

    // Clean base64 strings
    const cleanImage = imageBase64.replace(/^data:image\/\w+;base64,/, "");

    const parts: any[] = [
      {
        inlineData: {
          data: cleanImage,
          mimeType: "image/png",
        },
      }
    ];

    // If a mask is provided, we add it as a second image part
    let finalPrompt = prompt;

    // Fallback prompt if empty, ensuring API compliance
    if (!finalPrompt || finalPrompt.trim() === "") {
        finalPrompt = "Edit the image based on the provided context.";
    }

    if (maskBase64) {
      const cleanMask = maskBase64.replace(/^data:image\/\w+;base64,/, "");
      parts.push({
        inlineData: {
          data: cleanMask,
          mimeType: "image/png",
        }
      });
      finalPrompt = `${finalPrompt} (Note: The second image provided is a red mask indicating the area to edit. Only modify the masked area.)`;
    } else {
      // Global Edit / Clean
      finalPrompt = `${finalPrompt} Output high quality, photorealistic image.`;
    }

    parts.push({ text: finalPrompt });

    const config: any = {
      imageConfig: {
        aspectRatio: aspectRatio,
        numberOfImages: 1, 
      },
      safetySettings: [
        { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      ]
    };

    if (model === BananaModel.NANO_BANANA_PRO) {
       config.imageConfig.imageSize = "1K"; 
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: { parts },
      config: config
    });

    return extractImagesFromResponse(response);
  } catch (error: any) {
    console.error("Edit Image Error:", error);
    throw new Error(error.message || "图像编辑请求失败，请检查网络或更换模型尝试。");
  }
};

interface RecreateImageParams {
  model: BananaModel;
  referenceImageBase64: string;
  prompt: string;
  textContent?: string;
  textLayout?: string;
  aspectRatio: AspectRatio;
  numberOfImages: number;
  quality: ImageResolution;
}

export const recreateImageWithGemini = async ({
  model,
  referenceImageBase64,
  prompt,
  textContent,
  textLayout,
  aspectRatio,
  numberOfImages,
  quality
}: RecreateImageParams): Promise<string[]> => {
  try {
    const ai = await getClient(model);
    const cleanRef = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");

    // Construct a rich prompt including text instructions
    let fullPrompt = `Based on the reference image, generate a new image matching this description: ${prompt}.`;

    if (textContent) {
        fullPrompt += `\n\nInclude the following text in the image: "${textContent}".`;
    }
    if (textLayout) {
        fullPrompt += `\n\nText Layout Instructions: ${textLayout}`;
    }

    const parts = [
      {
        inlineData: {
          data: cleanRef,
          mimeType: "image/png", 
        },
      },
      {
        text: fullPrompt,
      },
    ];

    const config: any = {
      imageConfig: {
        aspectRatio: aspectRatio,
        numberOfImages: 1, 
      },
      safetySettings: [
        { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      ]
    };

    if (model === BananaModel.NANO_BANANA_PRO) {
      config.imageConfig.imageSize = quality;
    }

    // Handle multiple images via parallel requests if SDK doesn't support 'numberOfImages' for this model family
    const promises = Array.from({ length: numberOfImages }).map(() => 
      ai.models.generateContent({
        model: model,
        contents: { parts },
        config: config
      })
    );

    const responses = await Promise.all(promises);

    let allImages: string[] = [];
    responses.forEach(res => {
      allImages = [...allImages, ...extractImagesFromResponse(res)];
    });

    if (allImages.length === 0) {
      throw new Error("模型未返回图像，请检查提示词是否被安全策略拦截。");
    }

    return allImages;

  } catch (error: any) {
    console.error("Recreate Image Error:", error);
    throw new Error(error.message || "重塑创作请求失败，请稍后重试。");
  }
};

import React, { useState, useRef, useCallback } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);

  // Tools
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'none'>('none');
  const [brushSize, setBrushSize] = useState(40);
  const [isDrawing, setIsDrawing] = useState(false);

  // Data
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);

  // History for Undo (Stores ImageData)
  const [history, setHistory] = useState<ImageData[]>([]);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPos = useRef<{x: number, y: number} | null>(null);

  // Setup Canvas Context
  const getCtx = useCallback(() => {
    return canvasRef.current?.getContext('2d', { willReadFrequently: true });
  }, []);

  // Initialize Canvas
  const initCanvas = useCallback((width: number, height: number) => {
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (ctx) {
            ctx.clearRect(0, 0, width, height);
            const blankState = ctx.getImageData(0, 0, width, height);
            setHistory([blankState]);
        }
    }
  }, []);

  // Load Image
  const loadImage = useCallback((src: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setImage(src);
      setResultImages([]);
      setHistory([]);
      initCanvas(img.width, img.height);
    };
  }, [initCanvas]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
          if (evt.target?.result) loadImage(evt.target.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const useAsInput = (imgUrl: string) => {
     loadImage(imgUrl);
  };

  // --- UNDO LOGIC ---
  const saveSnapshot = () => {
      const ctx = getCtx();
      const canvas = canvasRef.current;
      if (ctx && canvas) {
          const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
          setHistory(prev => {
              const newHistory = [...prev, data];
              return newHistory.slice(-20);
          });
      }
  };

  const undo = () => {
      if (history.length <= 1) return;
      const newHistory = history.slice(0, -1);
      const prevState = newHistory[newHistory.length - 1];

      const ctx = getCtx();
      if (ctx && prevState) {
          ctx.putImageData(prevState, 0, 0);
          setHistory(newHistory);
      }
  };

  // --- DRAWING ENGINE ---
  const getCoordinates = (e: React.PointerEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none') return;
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDrawing(true);

    const { x, y } = getCoordinates(e);
    lastPos.current = { x, y };

    const ctx = getCtx();
    if (!ctx) return;

    // Drawing Config
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = brushSize;

    if (activeTool === 'eraser') {
        ctx.globalCompositeOperation = 'destination-out';
    } else {
        ctx.globalCompositeOperation = 'source-over';
        ctx.strokeStyle = '#ff0000'; 
    }

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    if (activeTool !== 'brush' && activeTool !== 'eraser') return;

    const { x, y } = getCoordinates(e);
    const ctx = getCtx();
    if (!ctx || !lastPos.current) return;

    ctx.beginPath();
    ctx.moveTo(lastPos.current.x, lastPos.current.y);
    ctx.lineTo(x, y);
    ctx.stroke();
    lastPos.current = { x, y };
  };

  const stopDrawing = (e: React.PointerEvent) => {
    if (isDrawing) {
        setIsDrawing(false);
        e.currentTarget.releasePointerCapture(e.pointerId);
        lastPos.current = null;
        saveSnapshot();

        // Reset composite operation to avoid affecting other ops
        const ctx = getCtx();
        if (ctx) ctx.globalCompositeOperation = 'source-over';
    }
  };

  // --- API ---
  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;
    setIsLoading(true);
    setError(null);

    try {
      let maskBase64: string | undefined = undefined;

      // Extract Mask only if not skipped and history shows edits
      if (!skipMask && canvasRef.current && history.length > 1) {
          maskBase64 = canvasRef.current.toDataURL('image/png');
      }

      const res = await editImageWithGemini({
        model,
        imageBase64: image,
        maskBase64,
        prompt: overridePrompt || prompt,
        aspectRatio: aspectRatio,
      });

      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePreset = (presetPrompt: string, ratio?: AspectRatio) => {
      setPrompt(presetPrompt);
      if (ratio) setAspectRatio(ratio);
  };

  const canClean = !!image; 

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">

      {/* LEFT COLUMN: EDITOR */}
      <div className="flex flex-col gap-4 h-full">

         {/* Top Toolbar */}
         <div className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex flex-wrap items-center justify-between gap-3 shrink-0">
            <div className="flex items-center gap-2">
                {!image ? (
                    <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg text-sm font-bold transition-colors shadow-lg shadow-yellow-500/10">
                        ➕ 上传图片
                        <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                    </label>
                ) : (
                    <>
                     <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-700">
                        <button 
                            onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                            className={`px-3 py-1.5 rounded text-sm flex items-center gap-2 font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            🖌️ 涂抹
                        </button>
                        <button 
                            onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                            className={`px-3 py-1.5 rounded text-sm flex items-center gap-2 font-medium transition-colors ${activeTool === 'eraser' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            🧼 橡皮擦
                        </button>
                     </div>
                     <button onClick={undo} disabled={history.length <= 1} className="p-2 text-gray-400 hover:text-white disabled:opacity-30 bg-gray-700 rounded hover:bg-gray-600 transition-colors" title="撤销上一步">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"></path></svg>
                     </button>
                     <button onClick={() => {setImage(null); setResultImages([]); setHistory([]);}} className="p-2 text-red-400 hover:text-red-300 hover:bg-red-900/30 rounded transition-colors" title="重置画布">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                     </button>
                    </>
                )}
            </div>

            {image && (activeTool === 'brush' || activeTool === 'eraser') && (
                <div className="flex items-center gap-2 bg-gray-900 px-3 py-1.5 rounded-lg border border-gray-700">
                    <span className="text-xs text-gray-400 font-bold">笔触大小</span>
                    <input 
                        type="range" min="5" max="100" 
                        value={brushSize} onChange={(e) => setBrushSize(Number(e.target.value))}
                        className="w-24 accent-yellow-500 h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer"
                    />
                </div>
            )}
         </div>

         {/* Canvas Area */}
         <div 
            ref={containerRef}
            className={`relative flex-1 bg-gray-900 border-2 rounded-xl overflow-hidden flex items-center justify-center transition-colors
                ${!image ? 'border-dashed border-gray-700' : 'border-gray-800 bg-[url("https://www.transparenttextures.com/patterns/stardust.png")]'}
            `}
         >
            {!image ? (
                <div className="text-center text-gray-600 pointer-events-none p-6">
                    <svg className="w-12 h-12 mx-auto mb-3 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    <p className="text-gray-500">拖拽或点击上传图片</p>
                </div>
            ) : (
                <div className="relative max-w-full max-h-full shadow-2xl">
                    <img src={image} className="max-w-full max-h-[50vh] object-contain block" alt="Source" draggable={false} />
                    {/* Canvas Overlay */}
                    <canvas 
                        ref={canvasRef}
                        onPointerDown={startDrawing}
                        onPointerMove={draw}
                        onPointerUp={stopDrawing}
                        onPointerLeave={stopDrawing}
                        className={`absolute inset-0 w-full h-full opacity-60 touch-none ${activeTool !== 'none' ? 'cursor-crosshair' : ''}`}
                    />
                </div>
            )}
            {!image && (
                 <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleFileUpload} />
            )}
         </div>

         {/* Bottom Controls */}
         <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 space-y-4 shrink-0">
             {/* Presets Row */}
             <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-2">
                    <p className="text-xs text-gray-400 font-bold uppercase tracking-wider">一键换幕</p>
                    <div className="flex gap-2">
                        <button onClick={() => handlePreset("Change the background to a professional green screen studio background.")} className="bg-gray-700 hover:bg-gray-600 text-xs px-2 py-1.5 rounded text-gray-200 border border-gray-600">🟢 绿幕</button>
                        <button onClick={() => handlePreset("Change the background to a professional blue screen studio background.")} className="bg-gray-700 hover:bg-gray-600 text-xs px-2 py-1.5 rounded text-gray-200 border border-gray-600">🔵 蓝幕</button>
                    </div>
                 </div>
                 <div className="space-y-2">
                    <p className="text-xs text-gray-400 font-bold uppercase tracking-wider">智能扩图</p>
                    <div className="flex gap-2">
                        <button onClick={() => handlePreset("Outpaint and expand the image to fill the canvas.", AspectRatio.SQUARE)} className="bg-gray-700 hover:bg-gray-600 text-xs px-2 py-1.5 rounded text-gray-200 border border-gray-600">1:1</button>
                        <button onClick={() => handlePreset("Outpaint and expand the image.", AspectRatio.PORTRAIT_4_5)} className="bg-gray-700 hover:bg-gray-600 text-xs px-2 py-1.5 rounded text-gray-200 border border-gray-600">4:5</button>
                        <button onClick={() => handlePreset("Outpaint and expand the image.", AspectRatio.PORTRAIT_9_16)} className="bg-gray-700 hover:bg-gray-600 text-xs px-2 py-1.5 rounded text-gray-200 border border-gray-600">9:16</button>
                    </div>
                 </div>
             </div>

             {/* Prompt & Generate */}
             <div className="space-y-3">
                 <div className="relative">
                    <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        placeholder="输入编辑指令 (例如：移除路人，将红花改为蓝花)..."
                        className="w-full bg-gray-900 border border-gray-600 rounded-lg p-3 text-sm text-white placeholder-gray-500 focus:ring-2 focus:ring-yellow-500 outline-none h-20 resize-none"
                    />
                 </div>

                 <div className="flex gap-3">
                     <Button 
                        onClick={() => handleGenerate()} 
                        disabled={!image} 
                        isLoading={isLoading} 
                        className="flex-1 py-3 bg-gradient-to-r from-yellow-500 to-amber-600 text-gray-900 shadow-lg shadow-yellow-500/20 font-bold"
                     >
                        ✨ 开始执行
                     </Button>
                     <Button 
                        onClick={() => handleGenerate("Remove text, watermarks, logos and subtitles.", true)}
                        disabled={!canClean} 
                        variant="secondary"
                        isLoading={isLoading} 
                        className="w-1/3 py-3 border border-gray-600 text-gray-300 hover:text-white"
                        title="无需涂抹，自动识别并清理"
                     >
                        🧼 一键清理
                     </Button>
                 </div>
             </div>
             {error && (
                <div className="bg-red-900/20 border border-red-800 rounded p-2 flex items-start gap-2">
                    <svg className="w-4 h-4 text-red-400 mt-0.5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    <p className="text-red-400 text-xs">{error}</p>
                </div>
             )}
         </div>
      </div>

      {/* RIGHT COLUMN: RESULTS */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 flex flex-col h-full overflow-hidden">
          <div className="flex items-center justify-between mb-4 px-1">
             <h3 className="text-lg font-bold text-white flex items-center gap-2">
                <span>🎨</span> 生成结果
             </h3>
             <span className="text-xs text-gray-500">点击结果可循环编辑</span>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-4">
             {resultImages.map((img, idx) => (
                 <div key={idx} className="group relative bg-black rounded-lg border border-gray-700 overflow-hidden shadow-lg">
                     <img src={img} alt="Result" className="w-full h-auto object-contain max-h-[500px]" />
                     <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all flex flex-col items-center justify-center gap-3 backdrop-blur-sm">
                        <Button onClick={() => useAsInput(img)} variant="primary" className="scale-90 hover:scale-100 text-xs">
                           🎨 作为底图继续
                        </Button>
                        <a href={img} download={`banana-edit-${Date.now()}.png`} className="text-white text-xs hover:underline hover:text-yellow-400 bg-black/50 px-3 py-1 rounded-full">
                           ⬇️ 下载图片
                        </a>
                     </div>
                 </div>
             ))}

             {resultImages.length === 0 && !isLoading && (
                 <div className="h-full flex flex-col items-center justify-center text-gray-600 opacity-40">
                    <svg className="w-16 h-16 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    <p>暂无生成结果</p>
                 </div>
             )}

             {isLoading && (
                 <div className="h-full flex flex-col items-center justify-center">
                    <div className="w-12 h-12 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-yellow-500 animate-pulse text-sm font-medium">AI 正在施展魔法...</p>
                 </div>
             )}
          </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);

  const [prompt, setPrompt] = useState('');
  const [textContent, setTextContent] = useState('');
  const [textLayout, setTextLayout] = useState('');

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.SQUARE);
  const [count, setCount] = useState(1);
  const [quality, setQuality] = useState<ImageResolution>(ImageResolution.RES_1K);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
             if(evt.target?.result) setRefImage(evt.target.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) {
        const reader = new FileReader();
        reader.onload = (evt) => {
             if(evt.target?.result) setRefImage(evt.target.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!refImage || !prompt) return;
    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt,
        textContent,
        textLayout,
        aspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const useAsReference = (imgUrl: string) => {
     setRefImage(imgUrl);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">

      {/* LEFT COLUMN: PARAMETERS */}
      <div className="flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">

        {/* Reference Image Uploader - Fixed height and object-contain */}
        <div 
          className={`shrink-0 bg-gray-900 rounded-xl border-2 border-dashed flex flex-col items-center justify-center transition-all relative group overflow-hidden
             ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-gray-700'}
             ${refImage ? 'border-solid border-gray-700 bg-black h-80' : 'h-48'}
          `}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {!refImage ? (
             <div className="text-center">
                <div className="w-12 h-12 bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-3 text-gray-500">
