          <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-4">
             {resultImages.map((img, idx) => (
                 <div key={idx} className="group relative bg-black rounded-lg border border-gray-700 overflow-hidden shadow-lg">
                     <img src={img} alt="Result" className="w-full h-auto object-contain max-h-[500px]" />
                     <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all flex flex-col items-center justify-center gap-3 backdrop-blur-sm">
                        <Button onClick={() => useAsInput(img)} variant="primary" className="scale-90 hover:scale-100 text-xs">
                           🎨 作为底图继续
                        </Button>
                        <a 
                          href={img} 
                          download={originalFileName || `banana-edit-${Date.now()}.png`} 
                          className="text-white text-xs hover:underline hover:text-yellow-400 bg-black/50 px-3 py-1 rounded-full"
                        >
                           ⬇️ 下载图片
                        </a>
                     </div>
                 </div>
             ))}

             {resultImages.length === 0 && !isLoading && (
                 <div className="h-full flex flex-col items-center justify-center text-gray-600 opacity-40">
                    <svg className="w-16 h-16 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    <p>暂无生成结果</p>
                 </div>
             )}

             {isLoading && (
                 <div className="h-full flex flex-col items-center justify-center">
                    <div className="w-12 h-12 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                    <p className="text-yellow-500 animate-pulse text-sm font-medium">AI 正在施展魔法...</p>
                 </div>
             )}
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [originalFileName, setOriginalFileName] = useState<string>('');

  // Initialize state from localStorage or default
  const [prompt, setPrompt] = useState(() => localStorage.getItem('banana_recreate_prompt') || '');
  const [textContent, setTextContent] = useState(() => localStorage.getItem('banana_recreate_content') || '');
  const [textLayout, setTextLayout] = useState(() => localStorage.getItem('banana_recreate_layout') || '');

  // Default to ORIGINAL, but try to load from storage if valid
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(() => 
    (localStorage.getItem('banana_recreate_ratio') as AspectRatio) || AspectRatio.ORIGINAL
  );

  const [count, setCount] = useState(() => {
    const saved = localStorage.getItem('banana_recreate_count');
    return saved ? Number(saved) : 1;
  });

  const [quality, setQuality] = useState<ImageResolution>(() => 
    (localStorage.getItem('banana_recreate_quality') as ImageResolution) || ImageResolution.RES_1K
  );

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  // Persistence Effects (Auto-save)
  useEffect(() => localStorage.setItem('banana_recreate_prompt', prompt), [prompt]);
  useEffect(() => localStorage.setItem('banana_recreate_content', textContent), [textContent]);
  useEffect(() => localStorage.setItem('banana_recreate_layout', textLayout), [textLayout]);
  useEffect(() => localStorage.setItem('banana_recreate_ratio', aspectRatio), [aspectRatio]);
  useEffect(() => localStorage.setItem('banana_recreate_count', count.toString()), [count]);
  useEffect(() => localStorage.setItem('banana_recreate_quality', quality), [quality]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
             if(evt.target?.result) {
                 setRefImage(evt.target.result as string);
                 setOriginalFileName(file.name);
                 setAspectRatio(AspectRatio.ORIGINAL);
             }
        };
        reader.readAsDataURL(file);
    }
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); };
  const handleDragLeave = (e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); };
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file && file.type.startsWith('image/')) {
        const reader = new FileReader();
        reader.onload = (evt) => {
             if(evt.target?.result) {
                 setRefImage(evt.target.result as string);
                 setOriginalFileName(file.name);
                 setAspectRatio(AspectRatio.ORIGINAL);
             }
        };
        reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!refImage || !prompt) return;
    setIsLoading(true);
    setError(null);
    setResults([]);

    try {
      const images = await recreateImageWithGemini({
        model,
        referenceImageBase64: refImage,
        prompt,
        textContent,
        textLayout,
        aspectRatio,
        numberOfImages: count,
        quality
      });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const useAsReference = (imgUrl: string) => {
     setRefImage(imgUrl);
     setAspectRatio(AspectRatio.ORIGINAL);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">

      {/* LEFT COLUMN: PARAMETERS */}
      <div className="flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">

        {/* Reference Image Uploader */}
        <div 
          className={`shrink-0 bg-gray-900 rounded-xl border-2 border-dashed flex flex-col items-center justify-center transition-all relative group overflow-hidden
             ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-gray-700'}
             ${refImage ? 'border-solid border-gray-700 bg-black h-80' : 'h-48'}
          `}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {!refImage ? (
             <div className="text-center">
                <div className="w-12 h-12 bg-gray-800 rounded-full flex items-center justify-center mx-auto mb-3 text-gray-500">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                </div>
                <label className="cursor-pointer text-yellow-500 hover:text-yellow-400 font-bold text-sm">
                    点击上传参考图
                    <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                </label>
                <p className="text-xs text-gray-500 mt-1">或拖拽图片至此</p>
             </div>
          ) : (
             <div className="relative w-full h-full flex items-center justify-center p-2">
               <img src={refImage} alt="Reference" className="max-w-full max-h-full object-contain" />
               <button 
                  onClick={() => {setRefImage(null); setOriginalFileName('');}}
                  className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white p-2 rounded-full transition-colors backdrop-blur-sm opacity-0 group-hover:opacity-100 shadow-lg"
               >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
               </button>
             </div>
          )}
        </div>

        {/* Control Panel */}
        <div className="bg-gray-800 border border-gray-700 rounded-xl p-5 space-y-5 flex-1">
           <div>
              <label className="block text-xs font-bold text-gray-400 mb-2 uppercase tracking-wider">创作描述 (Prompt)</label>
              <textarea 
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                className="w-full h-24 bg-gray-900 border border-gray-600 rounded-lg p-3 text-sm text-white focus:ring-2 focus:ring-yellow-500 outline-none resize-none placeholder-gray-500"
                placeholder="描述画面细节、风格、光影..."
              ></textarea>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                 <label className="block text-xs font-bold text-gray-400 mb-2 uppercase tracking-wider">图片文字内容</label>
                 <input 
                    type="text"
                    value={textContent}
                    onChange={(e) => setTextContent(e.target.value)}
                    className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-sm text-white focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="输入要显示的文字..."
                 />
              </div>
              <div>
                 <label className="block text-xs font-bold text-gray-400 mb-2 uppercase tracking-wider">文本排版指令</label>
                 <input 
                    type="text"
                    value={textLayout}
                    onChange={(e) => setTextLayout(e.target.value)}
                    className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-sm text-white focus:ring-2 focus:ring-yellow-500 outline-none"
                    placeholder="例如：居中显示，金色字体..."
                 />
              </div>
           </div>

           <div className="grid grid-cols-2 gap-4">
              <Select label="画幅比例" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                  <option value={AspectRatio.ORIGINAL}>保留原比例</option>
                  <option value={AspectRatio.SQUARE}>1:1 正方形</option>
                  <option value={AspectRatio.PORTRAIT_3_4}>3:4 竖幅</option>
                  <option value={AspectRatio.PORTRAIT_4_5}>4:5 竖幅</option>
                  <option value={AspectRatio.PORTRAIT_9_16}>9:16 手机全屏</option>
                  <option value={AspectRatio.LANDSCAPE_16_9}>16:9 宽屏</option>
              </Select>

              <Select label="最高画质 (4K仅限Pro)" value={quality} onChange={(e) => setQuality(e.target.value as ImageResolution)}>
                  <option value={ImageResolution.RES_1K}>标准 (1K)</option>
                  <option value={ImageResolution.RES_2K}>高清 (2K Pro)</option>
                  <option value={ImageResolution.RES_4K}>极清 (4K Pro)</option>
              </Select>
           </div>

           <div>
               <Select label="生成数量" value={count} onChange={(e) => setCount(Number(e.target.value))}>
                  <option value={1}>生成 1 张</option>
                  <option value={2}>生成 2 张</option>
                  <option value={3}>生成 3 张</option>
                  <option value={4}>生成 4 张</option>
               </Select>
           </div>

           <Button 
             onClick={handleGenerate} 
             disabled={!refImage || !prompt} 
             isLoading={isLoading}
             className="w-full py-4 text-lg font-bold shadow-xl shadow-yellow-900/10 mt-2"
           >
             🚀 开始重塑
           </Button>

           {error && (
             <div className="bg-red-900/20 border border-red-800 rounded p-2 text-center">
               <p className="text-red-400 text-xs">{error}</p>
             </div>
           )}
        </div>
      </div>

      {/* RIGHT COLUMN: RESULTS */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 h-full flex flex-col">
         <div className="flex items-center justify-between mb-4 px-1">
            <h3 className="text-lg font-bold text-white flex items-center gap-2">
                <span>🖼️</span> 创作成果
            </h3>
            <span className="text-xs text-gray-500">生成结果展示区</span>
         </div>

         <div className="flex-1 overflow-y-auto custom-scrollbar p-2">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               {results.map((imgUrl, idx) => (
                  <div key={idx} className="group relative rounded-lg overflow-hidden border border-gray-700 bg-black aspect-auto shadow-lg">
                     <img src={imgUrl} alt="Result" className="w-full h-full object-cover" />
                     <div className="absolute inset-0 bg-black/70 opacity-0 group-hover:opacity-100 transition-all flex flex-col items-center justify-center gap-3 backdrop-blur-sm p-4 text-center">
                        <Button onClick={() => useAsReference(imgUrl)} variant="primary" className="w-full text-xs py-1.5">
                           🔄 设为参考图
                        </Button>
                        <a 
                          href={imgUrl} 
                          download={originalFileName || `banana-recreate-${Date.now()}.png`} 
                          className="text-white text-xs hover:text-yellow-400 underline"
                        >
                           下载原图
                        </a>
                     </div>
                  </div>
               ))}
            </div>

            {results.length === 0 && !isLoading && (
                <div className="h-full flex flex-col items-center justify-center text-gray-600 opacity-40">
                   <div className="text-4xl mb-2">💡</div>
                   <p>等待灵感注入...</p>
                </div>
            )}

            {isLoading && (
                <div className="h-full flex flex-col items-center justify-center">
                   <div className="w-10 h-10 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin mb-3"></div>
                   <div className="animate-pulse text-yellow-500 font-mono text-sm">Gemini 正在重塑影像...</div>
                </div>
            )}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [originalFileName, setOriginalFileName] = useState<string>('');
  const [originalSize, setOriginalSize] = useState<{ width: number; height: number } | null>(null);

  // Presets State
  const [presets, setPresets] = useState<string[]>(() => {
    const saved = localStorage.getItem('banana_edit_presets');
    return saved ? JSON.parse(saved) : ["移除路人", "改为油画风格", "增强光影", "一键清理文字"];
  });

  // Tools
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'none'>('none');
  const [brushSize, setBrushSize] = useState(40);
  const [isDrawing, setIsDrawing] = useState(false);

  // Data
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);

  // Default to ORIGINAL
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);

  // History for Undo (Stores ImageData)
  const [history, setHistory] = useState<ImageData[]>([]);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPos = useRef<{x: number, y: number} | null>(null);

  // Persistence for presets
  useEffect(() => {
    localStorage.setItem('banana_edit_presets', JSON.stringify(presets));
  }, [presets]);

  // Setup Canvas Context
  const getCtx = useCallback(() => {
    return canvasRef.current?.getContext('2d', { willReadFrequently: true });
  }, []);

  // Initialize Canvas
  const initCanvas = useCallback((width: number, height: number) => {
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (ctx) {
            ctx.clearRect(0, 0, width, height);
            const blankState = ctx.getImageData(0, 0, width, height);
            setHistory([blankState]);
        }
    }
  }, []);

  // Load Image
  const loadImage = useCallback((src: string, name?: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setImage(src);
      setOriginalSize({ width: img.naturalWidth, height: img.naturalHeight });
      if (name) setOriginalFileName(name);
      setResultImages([]);
      setHistory([]);
      setAspectRatio(AspectRatio.ORIGINAL);
      initCanvas(img.width, img.height);
    };
  }, [initCanvas]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
          if (evt.target?.result) loadImage(evt.target.result as string, file.name);
        };
        reader.readAsDataURL(file);
    }
  };

  const useAsInput = (imgUrl: string) => {
     loadImage(imgUrl);
  };

  // --- PRESET LOGIC ---
  const savePreset = () => {
    if (prompt.trim() && !presets.includes(prompt.trim())) {
      setPresets([...presets, prompt.trim()]);
    }
  };

  const removePreset = (e: React.MouseEvent, p: string) => {
    e.stopPropagation();
    setPresets(presets.filter(item => item !== p));
  };

  // --- DOWNLOAD LOGIC (RESOLUTION PRESERVATION) ---
  const downloadResult = async (imgUrl: string) => {
    if (!originalSize) return;

    setIsLoading(true);
    try {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = imgUrl;
      await new Promise((resolve) => (img.onload = resolve));

      // Create a hidden canvas at ORIGINAL size
      const hiddenCanvas = document.createElement('canvas');
      hiddenCanvas.width = originalSize.width;
      hiddenCanvas.height = originalSize.height;
      const ctx = hiddenCanvas.getContext('2d');

      if (ctx) {
        // High quality scale back to original
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        ctx.drawImage(img, 0, 0, originalSize.width, originalSize.height);

        const dataUrl = hiddenCanvas.toDataURL('image/png', 1.0);
        const link = document.createElement('a');
        link.href = dataUrl;
        link.download = originalFileName || `banana-edit-${Date.now()}.png`;
        link.click();
      }
    } catch (err) {
      console.error("Download Error:", err);
      // Fallback to simple download
      const link = document.createElement('a');
      link.href = imgUrl;
      link.download = originalFileName || `banana-edit-${Date.now()}.png`;
      link.click();
    } finally {
      setIsLoading(false);
    }
  };

  // --- UNDO LOGIC ---
  const saveSnapshot = () => {
      const ctx = getCtx();
      const canvas = canvasRef.current;
      if (ctx && canvas) {
          const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
          setHistory(prev => [...prev, data].slice(-20));
      }
  };

  const undo = () => {
      if (history.length <= 1) return;
      const newHistory = history.slice(0, -1);
      const prevState = newHistory[newHistory.length - 1];
      const ctx = getCtx();
      if (ctx && prevState) {
          ctx.putImageData(prevState, 0, 0);
          setHistory(newHistory);
      }
  };

  const getCoordinates = (e: React.PointerEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  };

  const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none') return;
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDrawing(true);
    const { x, y } = getCoordinates(e);
    lastPos.current = { x, y };
    const ctx = getCtx();
    if (!ctx) return;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = brushSize;
    if (activeTool === 'eraser') ctx.globalCompositeOperation = 'destination-out';
    else { ctx.globalCompositeOperation = 'source-over'; ctx.strokeStyle = '#ff0000'; }
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const { x, y } = getCoordinates(e);
    const ctx = getCtx();
    if (!ctx || !lastPos.current) return;
    ctx.beginPath();
    ctx.moveTo(lastPos.current.x, lastPos.current.y);
    ctx.lineTo(x, y);
    ctx.stroke();
    lastPos.current = { x, y };
  };

  const stopDrawing = (e: React.PointerEvent) => {
    if (isDrawing) {
        setIsDrawing(false);
        e.currentTarget.releasePointerCapture(e.pointerId);
        lastPos.current = null;
        saveSnapshot();
        const ctx = getCtx();
        if (ctx) ctx.globalCompositeOperation = 'source-over';
    }
  };

  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;
    setIsLoading(true);
    setError(null);
    try {
      let maskBase64: string | undefined = undefined;
      if (!skipMask && canvasRef.current && history.length > 1) {
          maskBase64 = canvasRef.current.toDataURL('image/png');
      }
      const res = await editImageWithGemini({
        model,
        imageBase64: image,
        maskBase64,
        prompt: overridePrompt || prompt,
        aspectRatio: aspectRatio,
      });
      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePreset = (presetPrompt: string, ratio?: AspectRatio) => {
      setPrompt(presetPrompt);
      if (ratio) setAspectRatio(ratio);
  };

  const canClean = !!image; 

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">
      <div className="flex flex-col gap-4 h-full">
         <div className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex flex-wrap items-center justify-between gap-3 shrink-0">
            <div className="flex items-center gap-2">
                {!image ? (
                    <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg text-sm font-bold transition-colors shadow-lg shadow-yellow-500/10">
                        ➕ 上传图片
                        <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                    </label>
                ) : (
                    <>
                     <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-700">
                        <button 
                            onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')}
                            className={`px-3 py-1.5 rounded text-sm flex items-center gap-2 font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            🖌️ 涂抹
                        </button>
                        <button 
                            onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')}
                            className={`px-3 py-1.5 rounded text-sm flex items-center gap-2 font-medium transition-colors ${activeTool === 'eraser' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            🧼 橡皮擦
                        </button>
                     </div>
                     <button onClick={undo} disabled={history.length <= 1} className="p-2 text-gray-400 hover:text-white disabled:opacity-30 bg-gray-700 rounded hover:bg-gray-600 transition-colors">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"></path></svg>
                     </button>
                     <button onClick={() => {setImage(null); setOriginalFileName(''); setOriginalSize(null); setResultImages([]); setHistory([]);}} className="p-2 text-red-400 hover:text-red-300 hover:bg-red-900/30 rounded transition-colors">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                     </button>
                    </>
                )}
            </div>
            {image && (activeTool === 'brush' || activeTool === 'eraser') && (
                <div className="flex items-center gap-2 bg-gray-900 px-3 py-1.5 rounded-lg border border-gray-700">
                    <span className="text-xs text-gray-400 font-bold">笔触</span>
                    <input type="range" min="5" max="100" value={brushSize} onChange={(e) => setBrushSize(Number(e.target.value))} className="w-24 accent-yellow-500 h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer" />
                </div>
            )}
         </div>

         <div ref={containerRef} className={`relative flex-1 bg-gray-900 border-2 rounded-xl overflow-hidden flex items-center justify-center ${!image ? 'border-dashed border-gray-700' : 'border-gray-800'}`}>
            {!image ? (
                <div className="text-center text-gray-600 pointer-events-none p-6">
                    <svg className="w-12 h-12 mx-auto mb-3 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    <p>点击上传或拖拽图片</p>
                </div>
            ) : (
                <div className="relative max-w-full max-h-full shadow-2xl">
                    <img src={image} className="max-w-full max-h-[50vh] object-contain block" alt="Source" draggable={false} />
                    <canvas ref={canvasRef} onPointerDown={startDrawing} onPointerMove={draw} onPointerUp={stopDrawing} onPointerLeave={stopDrawing} className={`absolute inset-0 w-full h-full opacity-60 touch-none ${activeTool !== 'none' ? 'cursor-crosshair' : ''}`} />
                </div>
            )}
            {!image && <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleFileUpload} />}
         </div>

         <div className="bg-gray-800 p-4 rounded-xl border border-gray-700 space-y-4 shrink-0">
             <div className="flex flex-col gap-3">
                 <Select label="画幅比例 (扩图或锁定原比例)" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                    <option value={AspectRatio.ORIGINAL}>保留原比例</option>
                    <option value={AspectRatio.SQUARE}>1:1 正方形</option>
                    <option value={AspectRatio.PORTRAIT_4_5}>4:5 竖幅</option>
                    <option value={AspectRatio.PORTRAIT_9_16}>9:16 全屏</option>
                    <option value={AspectRatio.LANDSCAPE_16_9}>16:9 宽屏</option>
                 </Select>
                 <div className="space-y-2">
                    <div className="flex items-center justify-between">
                      <p className="text-xs text-gray-400 font-bold uppercase">常用指令预设</p>
                      <button onClick={savePreset} disabled={!prompt.trim()} className="text-[10px] text-indigo-400 hover:text-indigo-300 disabled:opacity-30">💾 存为预设</button>
                    </div>
                    <div className="flex flex-wrap gap-1.5 max-h-16 overflow-y-auto pb-1">
                        {presets.map((p, i) => (
                          <span key={i} onClick={() => setPrompt(p)} className="group flex items-center gap-1.5 bg-gray-900 border border-gray-700 hover:border-indigo-500 hover:bg-gray-850 px-2 py-1 rounded text-[11px] text-gray-300 cursor-pointer transition-all">
                             {p}
                             <span onClick={(e) => removePreset(e, p)} className="opacity-0 group-hover:opacity-100 hover:text-red-400 transition-opacity">×</span>
                          </span>
                        ))}
                    </div>
                 </div>
             </div>

             <div className="space-y-3">
                 <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="输入编辑指令 (例如：移除路人，改为日落光效)..." className="w-full bg-gray-900 border border-gray-600 rounded-lg p-3 text-sm text-white focus:ring-2 focus:ring-yellow-500 outline-none h-20 resize-none" />
                 <div className="flex gap-3">
                     <Button onClick={() => handleGenerate()} disabled={!image} isLoading={isLoading} className="flex-1 py-3 bg-gradient-to-r from-yellow-500 to-amber-600 text-gray-900 font-bold">✨ 开始执行</Button>
                     <Button onClick={() => handleGenerate("Remove text, logos and subtitlies.", true)} disabled={!canClean} variant="secondary" isLoading={isLoading} className="w-1/3 py-3 border border-gray-600 text-gray-300">🧼 清理文字</Button>
                 </div>
             </div>
             {error && <p className="text-red-400 text-xs bg-red-900/20 p-2 rounded">{error}</p>}
         </div>
      </div>

      <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 flex flex-col h-full overflow-hidden">
          <div className="flex items-center justify-between mb-4"><h3 className="text-lg font-bold text-white flex items-center gap-2">🎨 生成结果</h3><span className="text-xs text-gray-500">原图分辨率保留下载</span></div>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-4">
             {resultImages.map((img, idx) => (
                 <div key={idx} className="group relative bg-black rounded-lg border border-gray-700 overflow-hidden shadow-lg">
                     <img src={img} alt="Result" className="w-full h-auto object-contain max-h-[500px]" />
                     <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-all flex flex-col items-center justify-center gap-3 backdrop-blur-sm">
                        <Button onClick={() => useAsInput(img)} variant="primary" className="scale-90 text-xs">🎨 循环编辑</Button>
                        <button onClick={() => downloadResult(img)} className="text-white text-xs hover:text-yellow-400 bg-black/50 px-4 py-1.5 rounded-full border border-white/20">⬇️ 下载原分辨率</button>
                     </div>
                 </div>
             ))}
             {resultImages.length === 0 && !isLoading && <div className="h-full flex flex-col items-center justify-center text-gray-600 opacity-40"><p>暂无生成结果</p></div>}
             {isLoading && <div className="h-full flex flex-col items-center justify-center"><div className="w-12 h-12 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin mb-4"></div><p className="text-yellow-500 animate-pulse">正在处理中...</p></div>}
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BananaModel, AspectRatio, ImageResolution } from '../types';
import { recreateImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabRecreate: React.FC<Props> = ({ model }) => {
  const [refImage, setRefImage] = useState<string | null>(null);
  const [originalFileName, setOriginalFileName] = useState<string>('');

  // Presets State
  const [presets, setPresets] = useState<string[]>(() => {
    const saved = localStorage.getItem('banana_recreate_presets');
    return saved ? JSON.parse(saved) : ["极简极客风格", "赛博朋克霓虹", "复古胶片感", "清新自然光影", "3D 渲染质感"];
  });

  const [prompt, setPrompt] = useState(() => localStorage.getItem('banana_recreate_prompt') || '');
  const [textContent, setTextContent] = useState(() => localStorage.getItem('banana_recreate_content') || '');
  const [textLayout, setTextLayout] = useState(() => localStorage.getItem('banana_recreate_layout') || '');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(() => (localStorage.getItem('banana_recreate_ratio') as AspectRatio) || AspectRatio.ORIGINAL);
  const [count, setCount] = useState(() => Number(localStorage.getItem('banana_recreate_count') || 1));
  const [quality, setQuality] = useState<ImageResolution>(() => (localStorage.getItem('banana_recreate_quality') as ImageResolution) || ImageResolution.RES_1K);

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<string[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => { localStorage.setItem('banana_recreate_prompt', prompt); }, [prompt]);
  useEffect(() => { localStorage.setItem('banana_recreate_presets', JSON.stringify(presets)); }, [presets]);

  const savePreset = () => {
    if (prompt.trim() && !presets.includes(prompt.trim())) {
      setPresets([...presets, prompt.trim()]);
    }
  };

  const removePreset = (e: React.MouseEvent, p: string) => {
    e.stopPropagation();
    setPresets(presets.filter(item => item !== p));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
             if(evt.target?.result) {
                 setRefImage(evt.target.result as string);
                 setOriginalFileName(file.name);
                 setAspectRatio(AspectRatio.ORIGINAL);
             }
        };
        reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!refImage || !prompt) return;
    setIsLoading(true);
    setError(null);
    setResults([]);
    try {
      const images = await recreateImageWithGemini({ model, referenceImageBase64: refImage, prompt, textContent, textLayout, aspectRatio, numberOfImages: count, quality });
      setResults(images);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const useAsReference = (imgUrl: string) => {
     setRefImage(imgUrl);
     setAspectRatio(AspectRatio.ORIGINAL);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">
      <div className="flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">
        <div 
          className={`shrink-0 bg-gray-900 rounded-xl border-2 border-dashed flex flex-col items-center justify-center transition-all relative group overflow-hidden ${isDragging ? 'border-yellow-500 bg-gray-800' : 'border-gray-700'} ${refImage ? 'border-solid h-80' : 'h-48'}`}
          onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
          onDragLeave={() => setIsDragging(false)}
          onDrop={(e) => { e.preventDefault(); setIsDragging(false); const file = e.dataTransfer.files?.[0]; if (file?.type.startsWith('image/')) handleFileUpload({ target: { files: [file] } } as any); }}
        >
          {!refImage ? (
             <div className="text-center">
                <label className="cursor-pointer text-yellow-500 hover:text-yellow-400 font-bold text-sm">点击上传参考图<input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} /></label>
                <p className="text-xs text-gray-500 mt-1">控制画面的构图与色调</p>
             </div>
          ) : (
             <div className="relative w-full h-full flex items-center justify-center p-2"><img src={refImage} alt="Reference" className="max-w-full max-h-full object-contain" /><button onClick={() => {setRefImage(null); setOriginalFileName('');}} className="absolute top-2 right-2 bg-black/60 hover:bg-red-600 text-white p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity">×</button></div>
          )}
        </div>

        <div className="bg-gray-800 border border-gray-700 rounded-xl p-5 space-y-5 flex-1">
           <div className="space-y-3">
              <div className="flex items-center justify-between">
                <label className="text-xs font-bold text-gray-400 uppercase">创作描述 (Prompt)</label>
                <button onClick={savePreset} disabled={!prompt.trim()} className="text-[10px] text-indigo-400 hover:text-indigo-300">💾 存为预设</button>
              </div>
              <div className="flex flex-wrap gap-1.5">
                  {presets.map((p, i) => (
                    <span key={i} onClick={() => setPrompt(p)} className="group flex items-center gap-1.5 bg-gray-900 border border-gray-700 hover:border-indigo-500 hover:bg-gray-850 px-2 py-1 rounded text-[11px] text-gray-300 cursor-pointer transition-all">
                       {p}
                       <span onClick={(e) => removePreset(e, p)} className="opacity-0 group-hover:opacity-100 hover:text-red-400 transition-opacity">×</span>
                    </span>
                  ))}
              </div>
              <textarea value={prompt} onChange={(e) => setPrompt(e.target.value)} className="w-full h-24 bg-gray-900 border border-gray-600 rounded-lg p-3 text-sm text-white focus:ring-2 focus:ring-yellow-500 outline-none resize-none" placeholder="描述画面细节、风格、光影..." />
           </div>

           <div className="grid grid-cols-2 gap-4">
              <Select label="画幅比例" value={aspectRatio} onChange={(e) => setAspectRatio(e.target.value as AspectRatio)}>
                  <option value={AspectRatio.ORIGINAL}>保留原比例</option>
                  <option value={AspectRatio.SQUARE}>1:1 正方形</option>
                  <option value={AspectRatio.PORTRAIT_4_5}>4:5 竖幅</option>
                  <option value={AspectRatio.PORTRAIT_9_16}>9:16 全屏</option>
                  <option value={AspectRatio.LANDSCAPE_16_9}>16:9 宽屏</option>
              </Select>
              <Select label="最高画质" value={quality} onChange={(e) => setQuality(e.target.value as ImageResolution)}>
                  <option value={ImageResolution.RES_1K}>标准 (1K)</option>
                  <option value={ImageResolution.RES_2K}>高清 (2K Pro)</option>
                  <option value={ImageResolution.RES_4K}>极清 (4K Pro)</option>
              </Select>
           </div>

           <Button onClick={handleGenerate} disabled={!refImage || !prompt} isLoading={isLoading} className="w-full py-4 text-lg font-bold">🚀 开始重塑</Button>
           {error && <p className="text-red-400 text-xs text-center">{error}</p>}
        </div>
      </div>

      <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 h-full flex flex-col">
         <div className="flex items-center justify-between mb-4 px-1"><h3 className="text-lg font-bold text-white flex items-center gap-2">🖼️ 创作成果</h3></div>
         <div className="flex-1 overflow-y-auto custom-scrollbar p-2">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
               {results.map((imgUrl, idx) => (
                  <div key={idx} className="group relative rounded-lg overflow-hidden border border-gray-700 bg-black aspect-auto shadow-lg">
                     <img src={imgUrl} alt="Result" className="w-full h-full object-cover" />
                     <div className="absolute inset-0 bg-black/70 opacity-0 group-hover:opacity-100 transition-all flex flex-col items-center justify-center gap-3 backdrop-blur-sm p-4 text-center">
                        <Button onClick={() => useAsReference(imgUrl)} variant="primary" className="w-full text-xs py-1.5">🔄 设为参考图</Button>
                        <a href={imgUrl} download={originalFileName || `banana-recreate-${Date.now()}.png`} className="text-white text-xs hover:text-yellow-400 underline">下载原图</a>
                     </div>
                  </div>
               ))}
            </div>
            {results.length === 0 && !isLoading && <div className="h-full flex flex-col items-center justify-center text-gray-600 opacity-40"><p>等待灵感注入...</p></div>}
            {isLoading && <div className="h-full flex flex-col items-center justify-center"><div className="w-10 h-10 border-4 border-yellow-500 border-t-transparent rounded-full animate-spin mb-3"></div><div className="animate-pulse text-yellow-500 text-sm">Gemini 正在重塑影像...</div></div>}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [originalFileName, setOriginalFileName] = useState<string>('');
  const [originalSize, setOriginalSize] = useState<{ width: number; height: number } | null>(null);

  // Custom Presets State
  const [customPresets, setCustomPresets] = useState<string[]>(() => {
    const saved = localStorage.getItem('banana_edit_custom_presets');
    return saved ? JSON.parse(saved) : [];
  });
  const [showPresetMenu, setShowPresetMenu] = useState(false);

  // Tools
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'none'>('none');
  const [brushSize, setBrushSize] = useState(40);
  const [isDrawing, setIsDrawing] = useState(false);

  // Data
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);

  // Default to ORIGINAL
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);

  // History for Undo (Stores ImageData)
  const [history, setHistory] = useState<ImageData[]>([]);

  // Refs
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPos = useRef<{x: number, y: number} | null>(null);

  // Persistence for custom presets
  useEffect(() => {
    localStorage.setItem('banana_edit_custom_presets', JSON.stringify(customPresets));
  }, [customPresets]);

  // Setup Canvas Context
  const getCtx = useCallback(() => {
    return canvasRef.current?.getContext('2d', { willReadFrequently: true });
  }, []);

  // Initialize Canvas
  const initCanvas = useCallback((width: number, height: number) => {
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (ctx) {
            ctx.clearRect(0, 0, width, height);
            const blankState = ctx.getImageData(0, 0, width, height);
            setHistory([blankState]);
        }
    }
  }, []);

  // Load Image
  const loadImage = useCallback((src: string, name?: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setImage(src);
      setOriginalSize({ width: img.naturalWidth, height: img.naturalHeight });
      if (name) setOriginalFileName(name);
      setResultImages([]);
      setHistory([]);
      setAspectRatio(AspectRatio.ORIGINAL);
      initCanvas(img.width, img.height);
    };
  }, [initCanvas]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
          if (evt.target?.result) loadImage(evt.target.result as string, file.name);
        };
        reader.readAsDataURL(file);
    }
  };

  const useAsInput = (imgUrl: string) => {
     loadImage(imgUrl);
  };

  // --- PRESET LOGIC ---
  const saveCurrentAsPreset = () => {
    if (prompt.trim() && !customPresets.includes(prompt.trim())) {
      setCustomPresets([...customPresets, prompt.trim()]);
    }
  };

  const removeCustomPreset = (p: string) => {
    setCustomPresets(customPresets.filter(item => item !== p));
  };

  // --- DOWNLOAD LOGIC (RESOLUTION PRESERVATION) ---
  const downloadResult = async (imgUrl: string) => {
    if (!originalSize) return;

    setIsLoading(true);
    try {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = imgUrl;
      await new Promise((resolve) => (img.onload = resolve));

      // Create a hidden canvas at EXACT ORIGINAL size
      const hiddenCanvas = document.createElement('canvas');
      hiddenCanvas.width = originalSize.width;
      hiddenCanvas.height = originalSize.height;
      const ctx = hiddenCanvas.getContext('2d');

      if (ctx) {
        // High quality scale back to original resolution
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        ctx.drawImage(img, 0, 0, originalSize.width, originalSize.height);

        const dataUrl = hiddenCanvas.toDataURL('image/png', 1.0);
        const link = document.createElement('a');
        link.href = dataUrl;
        link.download = originalFileName || `banana-edit-${Date.now()}.png`;
        link.click();
      }
    } catch (err) {
      console.error("Resolution Preservation Download Error:", err);
      // Fallback
      const link = document.createElement('a');
      link.href = imgUrl;
      link.download = originalFileName || `banana-edit-${Date.now()}.png`;
      link.click();
    } finally {
      setIsLoading(false);
    }
  };

  // --- UNDO LOGIC ---
  const saveSnapshot = () => {
      const ctx = getCtx();
      const canvas = canvasRef.current;
      if (ctx && canvas) {
          const data = ctx.getImageData(0, 0, canvas.width, canvas.height);
          setHistory(prev => [...prev, data].slice(-20));
      }
  };

  const undo = () => {
      if (history.length <= 1) return;
      const newHistory = history.slice(0, -1);
      const prevState = newHistory[newHistory.length - 1];
      const ctx = getCtx();
      if (ctx && prevState) {
          ctx.putImageData(prevState, 0, 0);
          setHistory(newHistory);
      }
  };

  const getCoordinates = (e: React.PointerEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  };

  const startDrawing = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (activeTool === 'none') return;
    e.currentTarget.setPointerCapture(e.pointerId);
    setIsDrawing(true);
    const { x, y } = getCoordinates(e);
    lastPos.current = { x, y };
    const ctx = getCtx();
    if (!ctx) return;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = brushSize;
    if (activeTool === 'eraser') ctx.globalCompositeOperation = 'destination-out';
    else { ctx.globalCompositeOperation = 'source-over'; ctx.strokeStyle = '#ff0000'; }
    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const draw = (e: React.PointerEvent<HTMLCanvasElement>) => {
    if (!isDrawing) return;
    const { x, y } = getCoordinates(e);
    const ctx = getCtx();
    if (!ctx || !lastPos.current) return;
    ctx.beginPath();
    ctx.moveTo(lastPos.current.x, lastPos.current.y);
    ctx.lineTo(x, y);
    ctx.stroke();
    lastPos.current = { x, y };
  };

  const stopDrawing = (e: React.PointerEvent) => {
    if (isDrawing) {
        setIsDrawing(false);
        e.currentTarget.releasePointerCapture(e.pointerId);
        lastPos.current = null;
        saveSnapshot();
        const ctx = getCtx();
        if (ctx) ctx.globalCompositeOperation = 'source-over';
    }
  };

  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;
    setIsLoading(true);
    setError(null);
    try {
      let maskBase64: string | undefined = undefined;
      if (!skipMask && canvasRef.current && history.length > 1) {
          maskBase64 = canvasRef.current.toDataURL('image/png');
      }
      const res = await editImageWithGemini({
        model,
        imageBase64: image,
        maskBase64,
        prompt: overridePrompt || prompt,
        aspectRatio: aspectRatio,
      });
      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handlePreset = (presetPrompt: string) => {
      setPrompt(presetPrompt);
      setShowPresetMenu(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px]">
      <div className="flex flex-col gap-4 h-full">
         <div className="bg-gray-800 p-3 rounded-xl border border-gray-700 flex flex-wrap items-center justify-between gap-3 shrink-0">
            <div className="flex items-center gap-2">
                {!image ? (
                    <label className="cursor-pointer bg-yellow-500 hover:bg-yellow-400 text-gray-900 px-4 py-2 rounded-lg text-sm font-bold transition-colors shadow-lg shadow-yellow-500/10">
                        ➕ 上传图片
                        <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
                    </label>
                ) : (
                    <>
                     <div className="flex bg-gray-900 rounded-lg p-1 border border-gray-700">
                        <button onClick={() => setActiveTool(activeTool === 'brush' ? 'none' : 'brush')} className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'brush' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}>🖌️ 涂抹</button>
                        <button onClick={() => setActiveTool(activeTool === 'eraser' ? 'none' : 'eraser')} className={`px-3 py-1.5 rounded text-sm font-medium transition-colors ${activeTool === 'eraser' ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'}`}>🧼 橡皮擦</button>
                     </div>
                     <button onClick={undo} disabled={history.length <= 1} className="p-2 text-gray-400 hover:text-white disabled:opacity-30 bg-gray-700 rounded hover:bg-gray-600 transition-colors">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"></path></svg>
                     </button>
                     <button onClick={() => {setImage(null); setOriginalFileName(''); setOriginalSize(null); setResultImages([]); setHistory([]);}} className="p-2 text-red-400 hover:text-red-300 hover:bg-red-900/30 rounded transition-colors">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                     </button>
                    </>
                )}
            </div>
            {image && (activeTool === 'brush' || activeTool === 'eraser') && (
                <div className="flex items-center gap-2 bg-gray-900 px-3 py-1.5 rounded-lg border border-gray-700">
                    <span className="text-xs text-gray-400 font-bold">笔触</span>
                    <input type="range" min="5" max="100" value={brushSize} onChange={(e) => setBrushSize(Number(e.target.value))} className="w-24 accent-yellow-500 h-1.5 bg-gray-700 rounded-lg appearance-none cursor-pointer" />
                </div>
            )}
         </div>

