import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { BananaModel, AspectRatio, ImageResolution } from "../types";

// Helper to ensure API Key is ready, especially for Pro models
const getClient = async (model: BananaModel): Promise<GoogleGenAI> => {
  if (model === BananaModel.NANO_BANANA_PRO) {
    if (window.aistudio) {
      // Check for API key selection for Pro models
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  }

  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const extractImagesFromResponse = (response: any): string[] => {
  const images: string[] = [];

  if (!response.candidates || response.candidates.length === 0) {
    return images;
  }

  for (const candidate of response.candidates) {
    if (candidate.content && candidate.content.parts) {
      for (const part of candidate.content.parts) {
        if (part.inlineData) {
          const mimeType = part.inlineData.mimeType || 'image/png';
          const base64 = part.inlineData.data;
          images.push(`data:${mimeType};base64,${base64}`);
        }
      }
    }
  }
  return images;
};

interface EditImageParams {
  model: BananaModel;
  imageBase64: string; 
  maskBase64?: string; 
  prompt: string;
  aspectRatio: AspectRatio;
}

export const editImageWithGemini = async ({
  model,
  imageBase64,
  maskBase64,
  prompt,
  aspectRatio
}: EditImageParams): Promise<string[]> => {
  try {
    const ai = await getClient(model);

    // Clean base64 strings
    const cleanImage = imageBase64.replace(/^data:image\/\w+;base64,/, "");

    const parts: any[] = [
      {
        inlineData: {
          data: cleanImage,
          mimeType: "image/png",
        },
      }
    ];

    let finalPrompt = prompt;

    if (!finalPrompt || finalPrompt.trim() === "") {
        finalPrompt = "Edit the image based on the provided context.";
    }

    if (maskBase64) {
      const cleanMask = maskBase64.replace(/^data:image\/\w+;base64,/, "");
      parts.push({
        inlineData: {
          data: cleanMask,
          mimeType: "image/png",
        }
      });
      finalPrompt = `${finalPrompt} (System Note: The second image is a red mask. Only change the pixels covered by the mask. Keep the rest of the image identical.)`;
    } else {
      finalPrompt = `${finalPrompt} Output high quality, photorealistic image.`;
    }

    parts.push({ text: finalPrompt });

    const imageConfig: any = {
      numberOfImages: 1, 
    };

    if (aspectRatio !== AspectRatio.ORIGINAL) {
       imageConfig.aspectRatio = aspectRatio;
    }

    // REMOVED: No longer forcing 4K for Pro models to satisfy user request.
    // Default 1K is used for better performance and alignment with user preferences.

    const config: any = {
      imageConfig,
      safetySettings: [
        { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      ]
    };

    const response = await ai.models.generateContent({
      model: model,
      contents: { parts },
      config: config
    });

    return extractImagesFromResponse(response);
  } catch (error: any) {
    console.error("Edit Image Error:", error);
    throw new Error(error.message || "图像编辑请求失败，请检查网络或更换模型尝试。");
  }
};

interface RecreateImageParams {
  model: BananaModel;
  referenceImageBase64: string;
  prompt: string;
  textContent?: string;
  textLayout?: string;
  aspectRatio: AspectRatio;
  numberOfImages: number;
  quality: ImageResolution;
}

export const recreateImageWithGemini = async ({
  model,
  referenceImageBase64,
  prompt,
  textContent,
  textLayout,
  aspectRatio,
  numberOfImages,
  quality
}: RecreateImageParams): Promise<string[]> => {
  try {
    const ai = await getClient(model);
    const cleanRef = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");

    let fullPrompt = `Based on the reference image, generate a new image matching this description: ${prompt}.`;

    if (textContent) {
        fullPrompt += `\n\nInclude the following text in the image: "${textContent}".`;
    }
    if (textLayout) {
        fullPrompt += `\n\nText Layout Instructions: ${textLayout}`;
    }

    const parts = [
      {
        inlineData: {
          data: cleanRef,
          mimeType: "image/png", 
        },
      },
      {
        text: fullPrompt,
      },
    ];

    const imageConfig: any = {
      numberOfImages: 1, 
    };

    if (aspectRatio !== AspectRatio.ORIGINAL) {
       imageConfig.aspectRatio = aspectRatio;
    }

    // Keep quality settings for Recreation as requested previously through UI controls
    if (model === BananaModel.NANO_BANANA_PRO) {
      imageConfig.imageSize = quality;
    }

    const config: any = {
      imageConfig,
      safetySettings: [
        { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
        { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
      ]
    };

    const promises = Array.from({ length: numberOfImages }).map(() => 
      ai.models.generateContent({
        model: model,
        contents: { parts },
        config: config
      })
    );

    const responses = await Promise.all(promises);

    let allImages: string[] = [];
    responses.forEach(res => {
      allImages = [...allImages, ...extractImagesFromResponse(res)];
    });

    if (allImages.length === 0) {
      throw new Error("模型未返回图像，请检查提示词是否被安全策略拦截。");
    }

    return allImages;

  } catch (error: any) {
    console.error("Recreate Image Error:", error);
    throw new Error(error.message || "重塑创作请求失败，请稍后重试。");
  }
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { BananaModel, AspectRatio } from '../types';
import { editImageWithGemini } from '../services/geminiService';
import { Button } from './ui/Button';
import { Select } from './ui/Select';

interface Props {
  model: BananaModel;
}

interface Preset {
  name: string;
  content: string;
}

export const TabSmartEdit: React.FC<Props> = ({ model }) => {
  const [image, setImage] = useState<string | null>(null);
  const [originalFileName, setOriginalFileName] = useState<string>('');
  const [originalSize, setOriginalSize] = useState<{ width: number; height: number } | null>(null);

  // 自定义预设状态
  const [customPresets, setCustomPresets] = useState<Preset[]>(() => {
    const saved = localStorage.getItem('banana_smart_edit_presets_v5');
    return saved ? JSON.parse(saved) : [
      { name: "完美绿幕", content: "将背景替换为高饱和度的纯绿色 (#00ff29) 绿幕背景。" },
      { name: "纯蓝幕", content: "将背景替换为高饱和度的纯蓝色 (#0003ff) 蓝幕背景。" },
      { name: "去除戒指", content: "去除图片中人物手上的戒指，使手指看起来自然，没有饰品。" }
    ];
  });
  const [showPresetMenu, setShowPresetMenu] = useState(false);

  // 预设命名 UI 状态 (内置弹窗，非浏览器 prompt)
  const [isNamingPreset, setIsNamingPreset] = useState(false);
  const [tempPresetName, setTempPresetName] = useState('');

  // 工具状态
  const [activeTool, setActiveTool] = useState<'brush' | 'eraser' | 'none'>('none');
  const [brushSize, setBrushSize] = useState(40);
  const [isDrawing, setIsDrawing] = useState(false);

  // 数据状态
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [resultImages, setResultImages] = useState<string[]>([]);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.ORIGINAL);

  // 撤销历史
  const [history, setHistory] = useState<ImageData[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const lastPos = useRef<{x: number, y: number} | null>(null);

  // 预设持久化存储
  useEffect(() => {
    localStorage.setItem('banana_smart_edit_presets_v5', JSON.stringify(customPresets));
  }, [customPresets]);

  const getCtx = useCallback(() => canvasRef.current?.getContext('2d', { willReadFrequently: true }), []);

  const initCanvas = useCallback((width: number, height: number) => {
    const canvas = canvasRef.current;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d', { willReadFrequently: true });
        if (ctx) {
            ctx.clearRect(0, 0, width, height);
            const blankState = ctx.getImageData(0, 0, width, height);
            setHistory([blankState]);
        }
    }
  }, []);

  const loadImage = useCallback((src: string, name?: string) => {
    const img = new Image();
    img.src = src;
    img.onload = () => {
      setImage(src);
      // 记录原始分辨率
      setOriginalSize({ width: img.naturalWidth, height: img.naturalHeight });
      if (name) setOriginalFileName(name);
      setResultImages([]);
      setHistory([]);
      setAspectRatio(AspectRatio.ORIGINAL);
      initCanvas(img.width, img.height);
    };
  }, [initCanvas]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
          if (evt.target?.result) loadImage(evt.target.result as string, file.name);
        };
        reader.readAsDataURL(file);
    }
  };

  const useAsInput = (imgUrl: string) => loadImage(imgUrl);

  // 内置 UI 弹窗命名预设
  const openNamingModal = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!prompt.trim()) {
      alert("请先在指令框输入要保存的内容。");
      return;
    }
    setTempPresetName("自定义预设 " + (customPresets.length + 1));
    setIsNamingPreset(true);
  };

  const confirmSavePreset = () => {
    if (!tempPresetName.trim()) return;
    const newPreset = { name: tempPresetName.trim(), content: prompt.trim() };
    setCustomPresets(prev => [...prev, newPreset]);
    setIsNamingPreset(false);
    setShowPresetMenu(true);
  };

  const removeCustomPreset = (index: number) => {
    setCustomPresets(customPresets.filter((_, i) => i !== index));
  };

  // 核心优化：确保下载结果还原为上传时的【原始分辨率】
  const downloadResult = async (imgUrl: string) => {
    if (!originalSize) return;
    setIsLoading(true);
    try {
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = imgUrl;
      await new Promise((resolve) => (img.onload = resolve));

      const hiddenCanvas = document.createElement('canvas');
      // 设置为原始文件分辨率
      hiddenCanvas.width = originalSize.width;
      hiddenCanvas.height = originalSize.height;
      const ctx = hiddenCanvas.getContext('2d');

      if (ctx) {
        // 使用高质量图像平滑技术进行缩放还原
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';
        ctx.drawImage(img, 0, 0, originalSize.width, originalSize.height);

        const dataUrl = hiddenCanvas.toDataURL('image/png', 1.0);
        const link = document.createElement('a');
        link.href = dataUrl;
        link.download = originalFileName ? `edited-${originalFileName}` : `banana-edit-${Date.now()}.png`;
        link.click();
      }
    } catch (err) {
      console.error("Resolution Preservation Download Error:", err);
      const link = document.createElement('a');
      link.href = imgUrl;
      link.download = originalFileName ? `edited-${originalFileName}` : `banana-edit-${Date.now()}.png`;
      link.click();
    } finally {
      setIsLoading(false);
    }
  };

  const undo = () => {
      if (history.length <= 1) return;
      const newHistory = history.slice(0, -1);
      const prevState = newHistory[newHistory.length - 1];
      const ctx = getCtx();
      if (ctx && prevState) {
          ctx.putImageData(prevState, 0, 0);
          setHistory(newHistory);
      }
  };

  const getCoordinates = (e: React.PointerEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  };

  const handleGenerate = async (overridePrompt?: string, skipMask: boolean = false) => {
    if (!image) return;
    setIsLoading(true);
    setError(null);
    try {
      let maskBase64: string | undefined = undefined;
      if (!skipMask && canvasRef.current && history.length > 1) {
          maskBase64 = canvasRef.current.toDataURL('image/png');
      }
      const res = await editImageWithGemini({
        model,
        imageBase64: image,
        maskBase64,
        prompt: overridePrompt || prompt,
        aspectRatio: aspectRatio,
      });
      setResultImages(res);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const applyPreset = (content: string) => {
    setPrompt(content);
    setShowPresetMenu(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-[calc(100vh-140px)] min-h-[600px] relative">
